INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-23', E'산상수훈 (마태복음 5장)', E'마태복음 5장', E'갈릴리 산 위에서 예수님이 입을 여시며 하나님 나라의 새로운 질서가 선포됩니다. 산상수훈의 시작인 팔복은 세상이 추구하는 가치관을 완전히 뒤집어놓습니다. 심령이 가난한 자, 애통하는 자, 온유한 자가 복이 있다는 선언은 당시 청중들에게 충격이었을 것입니다. 세상은 부유함과 웃음과 강함을 복의 조건으로 여기지만, 예수님은 자신의 연약함을 인정하고 하나님께 전적으로 의지하는 자들이야말로 천국을 소유한다고 가르치십니다.\n\n예수님은 이렇게 복을 받은 자들의 정체성을 "너희는 세상의 소금이니... 너희는 세상의 빛이라"(마 5:13-14)고 규정하십니다. 소금은 부패를 막고 맛을 내며, 빛은 어둠을 몰아내고 길을 비춥니다. 그리스도인의 삶이 세상 속에서 갖는 본질적 기능을 보여주는 비유입니다. 그러나 맛을 잃은 소금, 감추어진 빛은 아무 소용이 없습니다. 착한 행실로 빛을 비추되, 그 목적이 자기 영광이 아니라 하늘 아버지께 영광을 돌리는 것이어야 함을 분명히 하십니다.\n\n이어지는 가르침에서 예수님은 율법의 참된 의미를 밝히십니다. 율법을 폐하러 오신 것이 아니라 완전하게 하러 오셨다는 선언과 함께, 외적 행위를 넘어 마음의 동기를 다루십니다. 살인하지 말라는 계명을 형제에 대한 분노의 문제로, 간음하지 말라는 계명을 음욕을 품는 마음의 문제로 확대하여 해석하십니다. 서기관과 바리새인들이 추구했던 외적이고 형식적인 의가 아니라, 마음에서 우러나오는 진정한 의를 요구하시는 것입니다.\n\n특별히 원수 사랑의 명령은 산상수훈의 절정을 이룹니다. "너희 원수를 사랑하며 너희를 박해하는 자를 위하여 기도하라"는 말씀은 인간의 본성과 상식을 뛰어넘는 하나님 나라의 윤리입니다. 악인과 선인에게 똑같이 해를 비추시고 비를 내리시는 하나님의 무차별적 사랑을 본받으라는 것입니다. 이것이 바로 "하늘에 계신 너희 아버지의 온전하심과 같이 너희도 온전하라"는 궁극적 부르심의 의미입니다.', E'오늘의 핵심\n예수님은 팔복을 통해 하나님 나라 백성의 성품을 제시하시고, 소금과 빛의 비유로 그들의 사명을 보여주시며, 율법의 참된 정신인 마음의 의와 원수 사랑을 가르치십니다.\n\n묵상 질문\n1. 나는 어떤 면에서 심령이 가난하며, 그것이 어떻게 천국을 소유하는 복이 될 수 있을까요?\n2. 내 삶이 소금의 맛을 잃지 않고 빛을 발하려면 무엇을 점검해야 할까요?\n3. 지금 내게 있는 분노나 미움을 예수님의 원수 사랑 명령 앞에 어떻게 내려놓을 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-24', E'산상수훈 (마태복음 6장)', E'마태복음 6장', E'마태복음 6장은 산상수훈의 중심부로서, 예수님께서 참된 의와 경건의 삶이 무엇인지 가르쳐 주십니다. 특히 ''은밀한 중에 보시는 아버지''라는 표현이 반복되면서, 하나님과의 관계가 외적인 종교 행위가 아닌 내면의 진실함에 기초해야 함을 보여줍니다.\n\n예수님은 먼저 구제와 기도와 금식을 예로 들어 경건의 동기를 점검하십니다. 외식하는 자들은 회당과 거리에서 나팔을 불며 구제하고, 사람들이 보는 곳에서 기도하며, 금식할 때 일부러 얼굴을 흉하게 합니다. 그들의 목적은 사람에게 칭찬받는 것이었고, 예수님은 "그들은 자기 상을 이미 받았느니라"고 말씀하십니다. 반면 하나님께서 기뻐하시는 것은 오른손이 하는 것을 왼손이 모르게 하는 구제, 골방에서 드리는 기도, 머리에 기름 바르고 얼굴을 씻으며 하는 금식입니다. 이것은 단순히 비밀스럽게 하라는 뜻이 아니라, 오직 하나님만을 의식하며 살라는 가르침입니다.\n\n이어서 예수님은 제자들에게 주기도문을 가르쳐 주십니다. 이방인들처럼 중언부언하지 말고, 하나님의 이름과 나라와 뜻을 먼저 구하며, 일용할 양식과 용서와 시험으로부터의 보호를 구하라고 하십니다. 특별히 용서에 대해서는 "너희가 사람의 잘못을 용서하면 너희 하늘 아버지께서도 너희 잘못을 용서하시려니와"(마 6:14)라고 강조하시면서, 하나님과의 관계가 이웃과의 관계와 분리될 수 없음을 가르치십니다.\n\n마지막으로 예수님은 보물을 하늘에 쌓으라고 말씀하시며, 하나님과 재물을 겸하여 섬길 수 없다고 선언하십니다. 그리고 공중의 새와 들의 백합화를 통해 하늘 아버지의 돌보심을 신뢰하라고 가르치십니다. 염려는 이방인들이 하는 것이며, 하나님의 자녀들은 먼저 그의 나라와 의를 구해야 합니다.\n\n마태복음 6장이 우리에게 던지는 도전은 분명합니다. 신앙생활이 사람들의 인정을 받기 위한 종교적 퍼포먼스가 되어서는 안 된다는 것입니다. 은밀한 중에 계신 아버지께서는 우리의 모든 필요를 아시고, 우리의 진심을 보십니다. 그분 앞에서 진실한 마음으로 살아갈 때, 비로소 우리는 참된 하나님 나라 백성의 삶을 살 수 있습니다.', E'오늘의 핵심\n예수님은 사람에게 보이려는 외식적인 경건이 아닌, 은밀한 중에 보시는 하나님 아버지 앞에서의 진실한 삶을 가르치십니다.\n\n묵상 질문\n1. 나의 구제와 기도와 금식은 누구를 향한 것인가요? 사람의 인정입니까, 하나님의 기쁨입니까?\n2. 주기도문을 통해 내가 먼저 구해야 할 것과 나중에 구할 것의 우선순위를 어떻게 정리하시겠습니까?\n3. 내일을 염려하는 대신 오늘 하나님의 나라와 의를 구하기 위해 무엇을 실천하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-26', E'산상수훈 (마태복음 7장)', E'마태복음 7장', E'산상수훈의 마지막 장인 마태복음 7장은 하나님 나라 백성이 일상에서 실천해야 할 구체적인 삶의 원칙들을 제시합니다. 예수님은 먼저 비판에 대해 경고하십니다. "너희가 비판하는 그 비판으로 너희가 비판을 받을 것"(마 7:2)이라는 말씀은 우리가 다른 사람을 판단하는 그 잣대가 결국 우리 자신에게 돌아온다는 엄중한 진리를 담고 있습니다. 형제의 눈 속에 있는 티와 내 눈 속에 있는 들보의 비유는 우리가 얼마나 자기 성찰 없이 타인을 정죄하기 쉬운지를 보여줍니다.\n\n이어지는 기도에 대한 가르침은 하늘 아버지의 성품을 드러냅니다. 예수님은 구하고, 찾고, 두드리라고 말씀하시며, 악한 부모도 자녀에게 좋은 것을 줄 줄 아는데 하물며 하늘 아버지께서 구하는 자에게 좋은 것으로 주시지 않겠느냐고 반문하십니다. 이는 하나님께서 우리의 필요를 아시고 응답하시는 선하신 아버지라는 확신을 심어줍니다.\n\n그러나 예수님은 동시에 좁은 문으로 들어가라고 도전하십니다. 멸망으로 인도하는 문은 크고 넓어서 많은 사람이 그리로 가지만, 생명으로 인도하는 문은 좁고 그 길이 협착합니다. 이는 신앙의 길이 결코 쉽지 않으며, 의도적인 선택과 헌신이 필요함을 보여줍니다. \n\n특별히 주목할 것은 거짓 선지자에 대한 경고와 열매로 나무를 아는 원리입니다. 겉모습이 아니라 삶의 열매로 진짜를 분별해야 합니다. 더 나아가 예수님은 "주여 주여" 부르며 주의 이름으로 많은 일을 행했다고 주장하는 사람들에게도 "내가 너희를 도무지 알지 못한다"고 말씀하실 수 있음을 경고하십니다. 중요한 것은 종교적 활동이 아니라 하늘 아버지의 뜻을 행하는 삶입니다.\n\n마지막으로 예수님은 말씀을 듣고 행하는 자와 듣기만 하는 자의 차이를 반석 위의 집과 모래 위의 집으로 비유하십니다. 인생의 폭풍이 몰아칠 때, 우리 신앙의 기초가 무엇인지가 드러납니다. 말씀을 듣는 것에서 그치지 않고 실천하는 삶이야말로 견고한 신앙의 토대가 됩니다.', E'오늘의 핵심\n예수님은 비판하지 말고, 끈질기게 구하며, 좁은 문으로 들어가고, 열매로 분별하며, 무엇보다 말씀을 듣고 행하는 삶을 살라고 가르치십니다.\n\n묵상 질문\n1. 나는 형제의 티를 지적하기 전에 내 눈의 들보를 먼저 보고 있나요?\n2. 좁은 문으로 들어가는 삶을 위해 내가 포기해야 할 것은 무엇인가요?\n3. 오늘 들은 말씀 중에 즉시 실천해야 할 것은 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-27', E'예수의 이적과 열두 제자 선택 (마태복음 8장)', E'마태복음 8장', E'산상수훈을 마치신 예수님께서 산에서 내려오시자 수많은 무리가 따릅니다. 그때 한센병 환자가 나아와 절하며 간구합니다. 당시 한센병 환자는 부정한 자로 여겨져 사람들에게 가까이 갈 수도 없었는데, 예수님께서는 손을 내밀어 그에게 직접 대시며 고쳐주십니다. 이는 율법이 금하는 접촉이었지만, 예수님의 사랑은 정결의 율법보다 더 큰 능력이었습니다.\n\n가버나움에서 만난 로마 백부장의 믿음은 더욱 놀라웠습니다. 이방인이면서도 그는 예수님의 권위를 정확히 이해하고 있었습니다. "다만 말씀으로만 하옵소서"(마 8:8)라는 그의 고백에서 우리는 말씀의 권위에 대한 온전한 신뢰를 봅니다. 예수님께서는 이스라엘 중에서도 이만한 믿음을 보지 못하셨다고 감탄하십니다. 하나님 나라는 혈통이나 민족이 아닌 믿음으로 들어가는 곳임을 보여주는 장면입니다.\n\n베드로의 장모를 고치신 후 저물 무렵, 사람들이 병든 자들을 데려왔을 때도 예수님께서는 한 사람도 돌려보내지 않으셨습니다. 이는 이사야 선지자가 예언한 "우리의 연약한 것을 친히 담당하시고 병을 짊어지셨다"는 말씀의 성취였습니다. \n\n그러나 예수님을 따르는 길은 결코 안락하지 않습니다. 여우도 굴이 있고 새도 거처가 있지만 인자는 머리 둘 곳이 없다고 말씀하십니다. 제자도의 길은 희생과 헌신을 요구합니다. 폭풍 속에서 주무시는 예수님의 모습은 제자들에게 큰 도전이 되었고, 가다라 지방에서 귀신 들린 자들을 고치신 일은 오히려 그 지방 사람들에게 두려움을 주어 예수님을 떠나가시도록 간구하게 만들었습니다.\n\n이 모든 일들은 예수님께서 단순히 기적을 행하는 분이 아니라, 인간의 고통과 연약함을 깊이 이해하시고 친히 담당하시는 메시아이심을 보여줍니다. 그분의 치유는 육체만이 아닌 영혼까지 온전케 하시는 구원의 손길이었습니다.', E'오늘의 핵심\n예수님께서는 말씀의 권위로 병자들을 고치시며, 사회에서 소외된 자들을 직접 만지시고 치유하심으로써 하나님의 긍휼과 구원의 능력을 나타내셨습니다.\n\n묵상 질문\n1. 한센병 환자에게 손을 대신 예수님처럼, 우리는 소외된 이웃을 어떻게 품을 수 있을까요?\n2. 백부장의 믿음처럼 말씀의 권위를 온전히 신뢰하는 믿음이 내게 있나요?\n3. 예수님을 따르는 제자도의 길에서 내가 내려놓아야 할 안락함은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-28', E'예수의 이적과 열두 제자 선택 (마태복음 9장)', E'마태복음 9장', E'갈릴리 호수를 건너 가버나움으로 돌아오신 예수님께 침상에 누운 중풍병자가 실려옵니다. 예수님께서는 병자를 메고 온 사람들의 믿음을 보시고 놀라운 선언을 하십니다. "작은 자야 안심하라 네 죄 사함을 받았느니라"(마 9:2). 육체의 치유를 구하러 온 이들에게 예수님께서는 먼저 영혼의 문제를 다루십니다. 이는 인간의 가장 근본적인 문제가 죄임을 보여주는 것이었습니다. 서기관들이 속으로 신성모독이라 비난하자, 예수님께서는 죄 사함의 권세와 병 고침의 권세가 모두 자신에게 있음을 중풍병자의 치유를 통해 증명하셨습니다.\n\n세관에 앉아있던 마태를 부르신 일은 예수님의 사역 방향을 분명히 보여줍니다. 당시 세리는 로마의 앞잡이로 민족의 배신자 취급을 받았습니다. 그런 마태의 집에서 세리와 죄인들과 함께 식사하시는 예수님을 바리새인들이 비난하자, 예수님께서는 의사가 병든 자에게 필요하듯 자신은 죄인을 부르러 왔다고 선포하십니다. 이어서 금식 논쟁을 통해 새로운 시대가 도래했음을 새 포도주와 새 부대의 비유로 설명하십니다. 예수님과 함께하는 지금은 혼인 잔치와 같은 기쁨의 때이며, 율법주의적 종교 체계로는 담을 수 없는 새로운 은혜의 시대가 열렸음을 선언하신 것입니다.\n\n회당장 야이로의 딸을 살리러 가시는 길에 열두 해 동안 혈루증을 앓던 여인이 예수님의 옷자락을 만집니다. 부정한 질병으로 소외되었던 이 여인의 믿음을 예수님께서는 공개적으로 인정하시며 치유하셨습니다. 죽은 소녀를 살리시고, 두 맹인의 눈을 뜨게 하시며, 귀신 들려 말 못하는 사람을 고치시는 일련의 기적들은 메시아 시대가 도래했음을 보여주는 표적들이었습니다. 그러나 바리새인들은 끝까지 예수님을 귀신의 왕을 의지한다고 비방합니다. 예수님께서는 이런 반대에도 불구하고 목자 없는 양 같은 무리를 불쌍히 여기시며 천국 복음을 전파하시고 병자를 고치셨습니다. 추수할 것은 많으나 일꾼이 적다는 말씀은 제자들을 향한 부르심이자 오늘 우리를 향한 초대이기도 합니다.', E'오늘의 핵심\n예수님께서는 죄 사함의 권세를 가지신 메시아로서 소외된 자들을 찾아가시고, 새로운 은혜의 시대를 여시며, 무리를 불쌍히 여기시는 참 목자의 모습을 보여주십니다.\n\n묵상 질문\n1. 예수님께서 중풍병자에게 먼저 죄 사함을 선언하신 이유는 무엇일까요?\n2. 세리와 죄인들과 함께 식사하신 예수님의 모습이 오늘날 교회에 주는 도전은 무엇인가요?\n3. 목자 없는 양 같은 이웃을 위해 나는 어떤 일꾼이 되어야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-29', E'예수의 이적과 열두 제자 선택 (마태복음 10장)', E'마태복음 10장', E'예수님께서는 열두 제자를 부르시며 그들에게 놀라운 권능을 주십니다. 더러운 귀신을 쫓아내고 모든 병과 연약함을 고치는 권세를 부여받은 제자들은 이제 예수님의 동역자가 되었습니다. 마태는 열두 사도의 이름을 기록하면서 자신을 ''세리 마태''라고 소개합니다. 세리라는 신분이 유대 사회에서 얼마나 천대받는 직업이었는지를 생각하면, 이는 자신의 과거를 부끄러워하면서도 그런 자신을 제자로 부르신 예수님께 대한 깊은 감사의 표현이었습니다.\n\n예수님께서는 제자들을 파송하시면서 먼저 "이스라엘 집의 잃어버린 양에게로 가라"고 명하십니다. 이방인의 길로도, 사마리아인의 고을에도 가지 말라는 말씀은 구원의 우선순위를 보여주는 것이었습니다. 제자들은 천국이 가까이 왔다는 메시지를 전하며, 병자를 고치고 죽은 자를 살리며 귀신을 쫓아내는 사역을 감당해야 했습니다. "거저 받았으니 거저 주라"는 예수님의 말씀은 복음 전파의 본질을 보여줍니다.\n\n그러나 예수님께서는 제자들이 당할 환난도 분명히 예고하십니다. 공회에 넘겨지고, 회당에서 채찍질당하며, 총독들과 임금들 앞에 끌려갈 것이라는 말씀은 복음 전파의 길이 결코 평탄하지 않음을 보여줍니다. 심지어 가족들조차 대적하여 죽음에 내어줄 것이라는 예언은 제자도의 극한 상황을 묘사합니다. 그럼에도 불구하고 예수님께서는 "두려워하지 말라"고 거듭 강조하십니다. 참새 한 마리도 하나님의 허락 없이는 땅에 떨어지지 않으며, 제자들의 머리털까지 세신 바 되었다는 말씀은 하나님의 세밀한 돌보심을 확증해 줍니다.\n\n예수님을 따르는 길은 자기 십자가를 지는 길입니다. 가족보다 예수님을 더 사랑해야 하며, 자기 목숨을 잃을 각오가 되어 있어야 합니다. 이는 단순한 희생이 아니라 영원한 생명을 얻는 역설적인 길입니다. 제자들을 영접하는 것이 곧 예수님을 영접하는 것이며, 작은 자에게 냉수 한 그릇을 주는 것조차도 하늘의 상급이 있다는 약속은 하나님 나라의 가치관을 보여줍니다.', E'오늘의 핵심\n예수님께서는 열두 제자를 부르시고 권능을 주시며 파송하시면서, 복음 전파의 사명과 그에 따르는 희생, 그리고 하나님의 돌보심과 영원한 상급을 약속하십니다.\n\n묵상 질문\n1. 세리였던 마태를 제자로 부르신 예수님의 은혜가 나의 삶에는 어떻게 나타나고 있나요?\n2. 복음을 위해 감당해야 할 희생과 고난 앞에서도 두려워하지 않을 수 있는 이유는 무엇일까요?\n3. 오늘 내가 냉수 한 그릇을 나누어야 할 ''작은 자''는 누구인지 기도하며 찾아보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-30', E'예수의 갈릴리 사역', E'마태복음 16장', E'아의 외치는 소리로 자신의 사명을 잘 감당했던 세례 요한은 헤롯이 동생의 아내를 취한 것을 비판한 일로 옥에 갇히고 헤로디아의 악한 계획으로 인해 죽임을 당하게 됩니다. 마태복음 14장에는 예수님을 따르던 큰 무리에게 행하신 예수님의 기적이 기록되어 있습니다. 예수님께서 하루 종일 말씀을 전하신 어느 날 날이 저물자 제자들이 와서 "무리를 보내어 마을에 들어가 먹을 것을 사 먹게 하소서"(마 14:15)라고 말합니다. 예수님께서 그들에게 먹을 것을 주라고 말씀하시자 제자들은 떡 다섯 개와 물고기 두 마리밖에 없다고 대답합니다. 예수님께서는 이 떡과 물고기들을 가지고 축사하신 후 제자들을 시켜서 나누어주게 하십니다.\n말씀을 듣던 무리에게 오병이어의 기적을 베푸셨던 이후 바다를 건너 제자들과 함께 게네사렛 땅으로 가십니다. 그리고 그곳의 많은 병든 자들이 예수님께 고침을 받습니다. 예수님께서는 귀신 들린 아이와 다리 저는 사람, 맹인과 말 못하는 사람 등 많은 이들을 고쳐주십니다. 예수님의 가르침과 이적을 경험한 많은 무리가 이를 놀랍게 여기며 하나님께 영광을 돌립니다.', E'오늘의 핵심\n예수님께서 보여주셨던 많은 기적은 사람들에게 하나님의 말씀을 전하고 약한 이웃들을 사랑하기 위한 그분의 방법이었습니다.\n\n묵상 질문\n예수님은 부족함 속에서도 감사하시고 나누시는 분이셨음을 어떻게 느끼셨나요?\n내가 가진 작은 것으로 누군가를 도울 수 있다고 믿으시나요?\n예수님처럼 부족함 속에서도 감사하고 나누는 사람이 되길 원하시나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-31', E'열두 제자 선택', E'마가복음 3장', E'예수님께서는 공생애를 시작하시면서 가장 먼저 하신 일이 있습니다. 바로 함께할 사람을 부르신 것입니다. 갈릴리 바닷가의 평범한 어부 시몬과 안드레, 야고보와 요한, 그리고 세관에 앉아 있던 레위까지 세상의 기준으로는 특별할 것 없는 사람들이었습니다. 그런데 예수님은 바로 그들을 택하셔서 열두 제자로 세우시고, 가르치고 고치는 사역을 함께 감당하게 하셨습니다.\n\n주목할 점은 예수님께서 혼자서도 충분히 모든 일을 하실 수 있었다는 것입니다. 회당에서 귀신을 내쫓으시고, 각종 병을 고치시며, 큰 무리에게 가르침을 주시는 분이셨습니다. 그럼에도 예수님은 사람을 부르셨습니다. 하나님의 일은 처음부터 ''함께''의 방식으로 설계되었기 때문입니다. 완벽해서 불린 것이 아니라, 부름받아 함께 걸으며 변화되는 것이 제자의 길입니다.\n\n또한 예수님의 사역을 비방하는 자들 앞에서도 예수님은 가르치기를 멈추지 않으셨습니다. "새 포도주는 새 부대에 넣느니라"는 말씀처럼, 예수님이 가져오신 복음은 기존의 틀에 억지로 끼워 맞출 수 없는 전혀 새로운 것이었습니다. 낡은 관습과 편견에 갇혀 있던 사람들에게 예수님은 새로운 시선으로 하나님 나라를 바라보라고 초청하신 것입니다.\n\n지금 내가 서 있는 자리가 어디든 직장이든, 학교든, 아직 방향을 찾는 중이든 예수님은 그 자리에서 나를 부르고 계십니다. 준비가 덜 된 것 같아도, 자격이 부족한 것 같아도 괜찮습니다. 어부의 그물가에서, 세관의 책상 앞에서 부르셨던 그 예수님이 오늘 나에게도 "나를 따르라"고 말씀하고 계십니다.\n\n오늘 나를 묶고 있는 ''낡은 부대'' 자격지심, 두려움, 익숙한 안전지대는 무엇인지 돌아보고, 예수님의 부르심 앞에 새롭게 응답하는 하루가 되기를 소망합니다.', E'오늘의 핵심\n예수님은 공생애를 시작하시면서 열두 제자를 선택하여 부르시고 그들을 가르치시며 함께 하나님 나라의 일들을 행하십니다.\n\n묵상 질문\n예수님이 제자들을 부르실 때 어떤 마음과 목적으로 그들을 선택하셨을까요?\n평신도인 내가 예수님의 제자로서 어떤 역할을 감당할 수 있을까요?\n예수님을 따르기 위해 내가 지금 내려놓아야 할 것은 무엇인지 기도해 보시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-02', E'예수의 이적과 가르침 (마가복음 7장)', E'마가복음 7장', E'바리새인들과 서기관들이 예루살렘에서 와서 예수님의 제자들이 손을 씻지 않고 음식을 먹는 모습을 보고 문제 삼았습니다. 유대인들에게 정결 예식은 단순한 위생 문제가 아니라 장로들의 전통을 지키는 신앙적 행위였습니다. 그런데 예수님은 이사야의 예언을 인용하시며 그들의 위선을 정면으로 지적하십니다. 입술로는 하나님을 공경한다고 하면서도 마음은 멀리 떠나 있었던 것입니다.\n\n예수님은 ''고르반''의 예를 들어 그들의 모순을 드러내십니다. 부모를 봉양해야 할 재물을 하나님께 드렸다고 선언하면 부모 공경의 의무를 면제받는 전통이었습니다. 하나님의 계명인 부모 공경을 사람의 전통으로 무력화시킨 것입니다. 예수님은 밖에서 들어가는 것이 사람을 더럽히는 것이 아니라, 마음에서 나오는 악한 생각과 탐욕, 교만이 사람을 더럽힌다고 선언하셨습니다. 정결의 본질은 외적 의식이 아니라 내면의 거룩함에 있었던 것입니다.\n\n이어서 예수님은 두로 지방으로 가셔서 수로보니게 여인을 만나십니다. 이방인이었던 그녀는 딸의 치유를 간구하며 "상 아래 개들도 아이들이 먹던 부스러기를 먹나이다"라고 겸손히 고백합니다. 형식적 정결함을 자랑하던 바리새인들과는 대조적으로, 그녀는 자신의 낮은 위치를 인정하면서도 예수님의 은혜를 갈망했습니다. 예수님은 그녀의 믿음을 보시고 딸을 고쳐주셨습니다.\n\n데가볼리 지방에서는 귀 먹고 말 더듬는 자를 고치십니다. 예수님은 그를 따로 데리고 가셔서 손가락을 그의 귀에 넣고 침을 뱉어 혀에 손을 대시며 "에바다" 곧 "열리라"고 명하셨습니다. 닫혔던 귀가 열리고 맺혔던 혀가 풀어진 것은 단순한 육체적 치유를 넘어, 하나님의 말씀을 듣고 찬양할 수 있게 된 영적 회복을 상징합니다. 사람들은 "그가 모든 것을 잘하였도다"라고 감탄했습니다. 예수님은 형식적 종교를 넘어 생명을 회복시키는 참된 구원자이셨습니다.', E'오늘의 핵심\n예수님은 외적 형식과 전통에 매인 종교적 위선을 지적하시고, 마음의 정결함과 진실한 믿음이 하나님께 나아가는 참된 길임을 보여주십니다.\n\n묵상 질문\n1. 내가 지키고 있는 신앙의 형식이 오히려 하나님의 뜻을 가로막고 있지는 않나요?\n2. 수로보니게 여인처럼 낮은 자리에서도 예수님의 은혜를 구하는 믿음이 내게 있나요?\n3. 막혔던 귀와 혀가 열린 것처럼, 내 삶에서 열려야 할 영적 감각은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-03', E'예수의 이적과 가르침 (마가복음 8장)', E'마가복음 8장', E'예수님께서 사천 명을 먹이시는 장면은 우리에게 하나님의 긍휼이 무엇인지 보여줍니다. 사흘이나 함께한 무리를 보시며 "내가 무리를 불쌍히 여기노라"고 말씀하시는 예수님의 마음에는 형식이 아닌 진정한 사랑이 있었습니다. 제자들은 광야에서 떡을 구할 길이 없다며 현실적인 한계를 이야기했지만, 예수님은 떡 일곱 개와 작은 생선 두어 마리로 기적을 행하셨습니다. 남은 조각이 일곱 광주리나 되었다는 기록은 하나님의 공급하심이 얼마나 넉넉한지를 증거합니다.\n\n그런데 바리새인들은 이런 놀라운 일을 목격하고도 하늘로부터 오는 표적을 요구했습니다. 예수님은 마음속으로 깊이 탄식하셨습니다. 이미 충분한 표적이 나타났음에도 그들의 눈은 여전히 닫혀 있었기 때문입니다. 예수님은 제자들에게 바리새인들의 누룩과 헤롯의 누룩을 주의하라고 경고하셨습니다. 이 누룩은 하나님의 일하심을 보고도 믿지 않는 불신앙과 교만을 가리킵니다.\n\n제자들조차도 영적으로 둔감했습니다. 떡이 없음을 걱정하는 그들에게 예수님은 오천 명과 사천 명을 먹이신 일을 상기시키셨습니다. 벳새다의 맹인이 단계적으로 시력을 회복하는 장면은 제자들의 영적 상태를 보여주는 듯합니다. 처음에는 나무 같은 것들이 걸어가는 것으로 보이다가, 다시 안수받은 후에야 모든 것을 밝히 보게 되었습니다.\n\n베드로의 고백 "주는 그리스도시니이다"는 영적 눈이 열린 순간을 보여줍니다. 그러나 예수님이 고난과 죽음을 예고하시자 베드로는 즉시 항변했습니다. 그는 메시아를 알아보았지만, 십자가의 길은 이해하지 못했던 것입니다. 예수님은 제자들에게 자기를 부인하고 자기 십자가를 지고 따르라고 말씀하셨습니다. 온 천하를 얻고도 목숨을 잃으면 무엇이 유익하겠느냐는 질문은 우리의 가치관을 뒤흔듭니다. 진정한 생명은 예수님과 복음을 위해 자기를 내려놓을 때 얻어진다는 역설적 진리가 여기에 있습니다.', E'오늘의 핵심\n예수님은 우리의 영적 눈을 열어 메시아를 알아보게 하시지만, 동시에 그 길이 십자가를 통과한다는 것을 가르치십니다. 참된 제자도는 자기를 부인하고 주님을 따르는 것입니다.\n\n묵상 질문\n1. 나는 일상에서 일어나는 하나님의 일하심을 얼마나 민감하게 알아차리고 있나요?\n2. 내가 가진 메시아에 대한 기대와 예수님이 보여주신 십자가의 길 사이에 어떤 간극이 있나요?\n3. 오늘 내가 져야 할 십자가는 무엇이며, 무엇을 위해 나를 내려놓아야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-04', E'예수의 예루살렘 입성과 대결 (마가복음 1장)', E'마가복음 1장', E'마가복음은 시작부터 강렬합니다. 이사야의 예언이 성취되며 세례 요한이 광야에 나타나 회개의 세례를 전파합니다. 낙타털 옷을 입고 메뚜기와 석청을 먹으며 사는 그의 모습은 구약의 선지자들을 연상시키지만, 그가 전하는 메시지는 새로운 시대의 도래를 알립니다. "나보다 능력 많으신 이가 내 뒤에 오시나니 나는 굽혀 그의 신발끈을 풀기도 감당하지 못하겠노라"(막 1:7). 요한은 자신의 역할을 정확히 알고 있었습니다. 물로 베푸는 회개의 세례를 넘어 성령으로 세례를 베푸실 분을 준비하는 것이었습니다.\n\n예수님이 요단강에서 세례를 받으실 때 일어난 일은 하나님 나라 역사의 결정적 전환점이었습니다. 하늘이 갈라지고 성령이 비둘기같이 내려오시며 "너는 내 사랑하는 아들이라"는 하늘의 선언이 울려 퍼집니다. 이는 단순한 인정이 아니라 메시아적 사명의 공식적 시작을 알리는 것이었습니다. 곧이어 성령은 예수님을 광야로 이끄셨고, 40일간의 시험을 통해 메시아로서의 길을 확증하게 하셨습니다.\n\n갈릴리에서 시작된 예수님의 공생애는 "때가 찼고 하나님의 나라가 가까이 왔으니 회개하고 복음을 믿으라"는 선포로 요약됩니다. 이 선포는 단지 말씀으로만 이루어진 것이 아니었습니다. 어부들을 부르시고, 회당에서 권위 있게 가르치시며, 귀신을 쫓아내시고, 병자를 고치시는 일들을 통해 하나님 나라의 능력이 구체적으로 나타났습니다. 사람들이 놀란 것은 그분의 가르침이 "권위 있는 자와 같고 서기관들과 같지 아니함"이었습니다. 귀신조차 예수님을 "하나님의 거룩한 자"로 알아보았습니다.\n\n특히 주목할 것은 예수님의 일상입니다. 밤늦도록 병자들을 고치신 후에도 "새벽 아직도 밝기 전에" 한적한 곳으로 가서 기도하셨습니다. 그리고 제자들이 찾아와 "모든 사람이 주를 찾나이다"라고 할 때, 예수님은 "다른 가까운 마을들로 가자"고 하십니다. 인기에 안주하지 않고 더 많은 영혼에게 복음을 전하려는 분명한 사명 의식이 있었습니다. 나병환자를 고치신 후 비밀을 지키라고 당부하신 것도 단순히 치유자가 아닌 복음 전파자로서의 사명을 잃지 않기 위함이었습니다. 마가복음 1장은 이렇게 권위와 능력, 그리고 분명한 사명을 가지신 하나님의 아들 예수 그리스도를 우리에게 소개합니다.', E'오늘의 핵심\n예수님은 하늘의 인정을 받은 하나님의 아들로서 권위 있는 가르침과 능력의 사역으로 하나님 나라의 도래를 선포하시며, 철저한 기도와 분명한 사명 의식으로 복음을 전파하십니다.\n\n묵상 질문\n1. 예수님의 권위가 서기관들과 다른 점은 무엇이며, 나는 어떤 권위로 살아가고 있나요?\n2. 예수님처럼 새벽에 기도하며 하나님과의 교제를 우선순위에 두고 있나요?\n3. "때가 찼고 하나님 나라가 가까이 왔다"는 선포가 내 삶에서는 어떻게 구현되고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-05', E'예수의 예루살렘 입성과 대결 (마가복음 2장)', E'마가복음 2장', E'가버나움의 한 집에 예수님이 계시다는 소식이 전해지자 사람들이 문전성시를 이룹니다. 그런데 네 사람이 중풍병자 친구를 데려왔다가 인파에 막히자 놀라운 일을 벌입니다. 지붕을 뜯어 구멍을 내고 친구를 달아 내린 것입니다. 그들의 간절함과 믿음을 보신 예수님은 중풍병자에게 "네 죄 사함을 받았느니라"고 선언하십니다. 병 고침을 기대했는데 죄 사함을 선포하신 것입니다. 이는 육신의 치유보다 영혼의 회복이 더 근본적임을 보여주는 동시에, 예수님이 죄를 사하는 신적 권위를 가지신 분임을 드러내는 선언이었습니다. \n\n서기관들이 마음속으로 "신성 모독"이라고 반발하자, 예수님은 그들의 생각을 꿰뚫어 보시고 중풍병자를 즉시 일으켜 세우십니다. 죄 사함의 권세를 가시적으로 입증하신 것입니다. 이어서 세리 레위를 제자로 부르시고 죄인들과 함께 식탁 교제를 나누시는 모습은 당시 종교 지도자들에게는 충격적이었습니다. 그러나 예수님은 분명히 말씀하십니다. "나는 의인을 부르러 온 것이 아니요 죄인을 부르러 왔노라." 의사가 병든 자에게 필요하듯, 구원자는 죄인에게 필요하다는 은혜의 선언입니다.\n\n혼인 잔치의 비유와 새 포도주 비유는 예수님이 가져오신 하나님 나라의 새로운 차원을 보여줍니다. 율법의 형식에 갇힌 낡은 틀로는 복음의 생명력을 담아낼 수 없습니다. 안식일에 밀 이삭을 자른 제자들을 비난하는 바리새인들에게 예수님은 안식일의 참 의미를 일깨우십니다. "안식일이 사람을 위하여 있는 것이요 사람이 안식일을 위하여 있는 것이 아니니." 율법의 정신은 생명을 살리는 것이지 속박하는 것이 아닙니다. 인자이신 예수님은 안식일의 주인으로서 참된 안식, 곧 죄로부터의 해방과 하나님과의 화목을 주시는 분이십니다.', E'오늘의 핵심\n예수님은 죄를 사하는 권세와 안식일의 주인 되심을 선포하시며, 율법의 형식이 아닌 생명을 살리는 은혜의 복음을 보여주십니다.\n\n묵상 질문\n1. 지붕을 뜯을 정도로 간절히 예수님께 나아가야 할 내 삶의 문제는 무엇인가요?\n2. 내가 붙잡고 있는 종교적 형식이 오히려 은혜를 가로막고 있지는 않나요?\n3. 예수님이 죄인을 부르러 오셨다는 말씀이 나에게는 어떤 위로와 도전이 되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-06', E'예수의 예루살렘 입성과 대결 (마가복음 3장)', E'마가복음 3장', E'안식일 회당에서 한쪽 손 마른 사람을 고치신 예수님의 모습은 하나님 나라의 본질이 무엇인지를 분명하게 보여줍니다. 사람들이 예수님을 고발하려고 주시하는 가운데, 예수님은 "안식일에 선을 행하는 것과 악을 행하는 것, 생명을 구하는 것과 죽이는 것, 어느 것이 옳으냐"고 물으셨습니다. 종교적 규정에 갇혀 있던 바리새인들과 달리, 예수님에게 안식일은 생명을 살리고 회복시키는 날이었습니다.\n\n이후 예수님은 산에 오르셔서 열두 제자를 세우십니다. 흥미로운 점은 예수님께서 그들을 부르신 목적이 단순히 일을 시키기 위함이 아니었다는 것입니다. "자기와 함께 있게 하시고"라는 표현이 이를 잘 보여줍니다. 예수님은 제자들이 먼저 자신과 함께 머물며 배우고 성장하기를 원하셨습니다. 그 다음에야 전도하고 귀신을 내쫓는 권능을 주셨습니다. 함께함이 먼저이고, 사역은 그 다음이었습니다.\n\n예수님의 사역이 확장되면서 반대도 거세졌습니다. 심지어 가족들조차 예수님을 이해하지 못했고, 서기관들은 귀신의 왕 바알세불의 힘을 빌렸다고 비난했습니다. 그러나 예수님은 이런 오해와 비난 속에서도 하나님 나라의 진리를 가르치기를 멈추지 않으셨습니다. 특히 성령을 모독하는 죄의 심각성을 경고하시며, 하나님의 역사를 악으로 규정하는 것이 얼마나 위험한지를 일깨우셨습니다.\n\n마가복음 3장의 마지막 부분에서 예수님은 혈육을 넘어선 새로운 가족 개념을 제시하십니다. "누구든지 하나님의 뜻대로 행하는 자가 내 형제요 자매요 어머니"라는 선언은 하나님 나라의 공동체가 혈연이 아닌 순종으로 맺어진다는 것을 보여줍니다. 예수님을 따르는 제자의 길은 바로 이런 새로운 관계 속으로 들어가는 것입니다.', E'오늘의 핵심\n예수님은 안식일의 참된 의미를 회복시키시고, 열두 제자를 세워 함께하시며, 하나님의 뜻대로 행하는 자들이 진정한 가족임을 선포하십니다.\n\n묵상 질문\n1. 종교적 규정보다 생명을 우선시하신 예수님의 마음을 내 삶에서 어떻게 실천할 수 있을까요?\n2. 예수님께서 제자들을 ''함께 있게 하신'' 것처럼, 나는 예수님과 함께하는 시간을 얼마나 가지고 있나요?\n3. 하나님의 뜻대로 행하는 삶이란 구체적으로 어떤 모습일지 기도하며 묵상해 보시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-07', E'예수의 예루살렘 입성과 대결 (마가복음 4장)', E'마가복음 4장', E'마가복음 4장은 예수님께서 바닷가에서 큰 무리를 가르치시는 장면으로 시작됩니다. 워낙 많은 사람이 모여들어 예수님은 배에 오르셔야 했고, 무리는 육지에 서서 말씀을 들었습니다. 이날 예수님은 여러 비유로 하나님 나라의 비밀을 가르치셨습니다.\n\n씨 뿌리는 자의 비유는 말씀이 우리 마음에 어떻게 심기고 자라는지를 보여줍니다. 같은 씨앗이지만 떨어진 땅의 상태에 따라 전혀 다른 결과를 맺습니다. 길가에 떨어진 씨는 새들이 먹어버리고, 돌밭에 떨어진 씨는 뿌리를 내리지 못해 말라버립니다. 가시떨기에 떨어진 씨는 세상 염려와 재물의 유혹에 막혀 결실하지 못합니다. 오직 좋은 땅에 떨어진 씨만이 삼십 배, 육십 배, 백 배의 결실을 맺습니다. 예수님은 이 비유를 통해 말씀을 듣는 우리의 마음 상태가 얼마나 중요한지를 가르쳐 주십니다.\n\n이어지는 겨자씨 비유는 하나님 나라의 놀라운 성장력을 보여줍니다. 땅 위의 모든 씨보다 작은 겨자씨가 자라면 모든 풀보다 커져 새들이 깃들 만큼 큰 나무가 됩니다. 하나님 나라는 비록 작고 보잘것없이 시작되지만, 그 안에는 생명력이 있어 놀랍게 성장합니다.\n\n하루 종일 가르치신 예수님은 저녁이 되자 제자들에게 "우리가 저편으로 건너가자"고 하십니다. 지친 몸으로 배 고물에서 베개를 베고 주무시는 모습은 우리와 같은 육신의 연약함을 지니신 인간 예수님의 모습입니다. 그런데 갑자기 큰 광풍이 일어나 물이 배에 가득 차게 됩니다. 제자들이 두려움에 떨며 예수님을 깨우자, 주님은 일어나 바람을 꾸짖으시고 바다를 잠잠케 하십니다. "그가 누구이기에 바람과 바다도 순종하는가"라는 제자들의 물음은 예수님의 정체성에 대한 근본적인 질문입니다. 방금 전까지 피곤에 지쳐 주무시던 분이 창조주의 권능으로 자연을 다스리시는 것입니다.\n\n이 하루의 여정은 예수님이 누구신지를 점진적으로 보여줍니다. 말씀의 교사이시면서 동시에 만물을 다스리시는 주님이십니다. 우리 삶의 풍랑 속에서도 주님은 함께 계시며, 그분의 한 말씀이면 모든 것이 잠잠해집니다.', E'오늘의 핵심\n예수님은 비유를 통해 하나님 나라의 비밀을 가르치시고, 자연을 다스리시는 권능으로 자신이 하나님의 아들이심을 나타내십니다.\n\n묵상 질문\n1. 내 마음의 밭은 지금 어떤 상태인가요? 말씀의 씨앗이 잘 자랄 수 있는 좋은 땅인가요?\n2. 겨자씨처럼 작게 시작된 내 믿음이 어떻게 성장하고 있는지 돌아보셨나요?\n3. 인생의 풍랑 속에서 예수님이 함께 계심을 경험한 적이 있나요? 그때 주님은 어떻게 역사하셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-09', E'예수의 예루살렘 입성과 대결 (마가복음 5장)', E'마가복음 5장', E'거라사 지방의 무덤 사이에는 아무도 제어할 수 없는 한 사람이 있었습니다. 쇠사슬로도 묶을 수 없고, 밤낮으로 소리 지르며 돌로 자기 몸을 해치던 그는 완전히 소외된 존재였습니다. 예수님께서는 바로 이 한 영혼을 위해 풍랑을 뚫고 바다를 건너오셨습니다. 군대 귀신이라 불리는 수많은 악한 영들이 그를 사로잡고 있었지만, 예수님의 권능 앞에서는 무력했습니다. 돼지 이천 마리가 바다에 몰사하는 엄청난 경제적 손실이 발생했지만, 예수님께는 한 영혼의 회복이 그 무엇보다 소중했습니다. 회복된 그 사람은 이제 옷을 입고 정신이 온전하여 예수님 곁에 앉아 있었습니다.\n\n다시 바다를 건너온 예수님을 회당장 야이로가 찾아옵니다. 딸이 죽어가고 있다는 절박함에 체면도 버리고 예수님 발 아래 엎드립니다. 그런데 그 급한 길에 열두 해 동안 혈루증을 앓던 여인이 나타납니다. 율법상 부정한 여인이었던 그녀는 무리 속에 몰래 끼어들어 예수님의 옷자락을 만집니다. "내가 그의 옷에만 손을 대어도 구원을 받으리라"(막 5:28)는 그녀의 믿음은 즉시 응답받았습니다. 예수님은 급한 걸음을 멈추시고 그녀를 찾아 "딸아 네 믿음이 너를 구원하였으니 평안히 가라"고 축복하십니다.\n\n그 사이 야이로의 딸이 죽었다는 소식이 전해집니다. 절망적인 순간, 예수님은 "두려워하지 말고 믿기만 하라"고 말씀하십니다. 죽음의 권세조차 예수님 앞에서는 잠시 잠든 것에 불과했습니다. "달리다굼" 한마디에 열두 살 소녀는 일어나 걷기 시작합니다. \n\n이 세 가지 이야기는 모두 절망적인 상황에서 예수님을 만난 사람들의 이야기입니다. 사회에서 버림받은 자, 율법적으로 부정한 자, 죽음 앞에 무력한 자들. 그러나 예수님은 그 어떤 절망도 뛰어넘는 생명의 주권자이심을 보여주십니다. 오늘 우리가 처한 상황이 아무리 막막해도, 예수님께는 불가능이 없음을 기억합시다.', E'오늘의 핵심\n예수님은 사회에서 소외된 자, 율법적으로 부정한 자, 죽음의 권세 아래 있는 자 모두를 찾아오셔서 온전한 회복과 생명을 주시는 구원자이십니다.\n\n묵상 질문\n1. 거라사 지방 사람들은 왜 영혼의 구원보다 경제적 손실에 더 마음이 쓰였을까요?\n2. 혈루증 여인처럼 절박한 믿음으로 예수님께 나아간 경험이 있으신가요?\n3. "두려워하지 말고 믿기만 하라"는 말씀이 오늘 내 상황에 어떻게 적용될 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-10', E'예수의 예루살렘 입성과 대결 (마가복음 6장)', E'마가복음 6장', E'마가복음 6장은 예수님의 사역이 더욱 확장되면서도 동시에 거부당하는 역설적인 모습을 보여줍니다. 고향 나사렛에서 예수님은 회당에서 가르치셨지만, 사람들은 그를 ''마리아의 아들 목수''로만 기억하며 배척했습니다. 그들에게 예수님은 어린 시절부터 함께 자란 평범한 이웃일 뿐이었고, 하나님의 아들이라는 사실을 받아들일 수 없었던 것입니다. 놀랍게도 예수님은 그들의 불신앙으로 인해 고향에서는 큰 권능을 행하실 수 없었습니다. 이는 믿음이 하나님의 역사를 경험하는 통로임을 보여주는 중요한 장면입니다.\n\n이어서 예수님은 열두 제자를 둘씩 짝지어 파송하시며, 그들에게 권능을 주시되 철저히 하나님만 의지하도록 가르치십니다. 지팡이 외에는 아무것도 가지지 말라는 명령은 제자들이 자신의 준비나 능력이 아닌 오직 하나님의 공급하심을 경험하도록 하신 것입니다. 한편 헤롯은 세례 요한을 의롭게 여기면서도 헤로디아와의 불륜 관계를 끊지 못했고, 결국 딸의 춤에 취해 충동적으로 한 맹세로 요한을 죽이게 됩니다. 양심의 소리를 들으면서도 죄의 길에서 돌이키지 못한 헤롯의 모습은 우리에게 경고가 됩니다.\n\n오병이어의 기적은 예수님의 긍휼하심이 가장 잘 드러나는 사건입니다. 목자 없는 양 같은 무리를 불쌍히 여기신 예수님은 피곤하신 중에도 그들을 가르치시고, 제자들이 가진 작은 것으로 오천 명을 먹이십니다. 이후 예수님은 기도하러 산으로 가셨고, 제자들은 역풍을 만나 밤새 노를 젓습니다. 새벽녘 물 위를 걸어오신 예수님을 본 제자들은 유령인 줄 알고 두려워했지만, "안심하라 내니 두려워하지 말라"는 음성에 평안을 얻습니다. 그러나 제자들은 여전히 예수님이 누구신지 온전히 깨닫지 못했습니다. 떡을 떼시던 기적을 보고도 그 의미를 이해하지 못한 그들의 둔한 마음은, 우리도 종종 하나님의 역사를 경험하면서도 그 의미를 놓치고 있음을 돌아보게 합니다.', E'오늘의 핵심\n예수님은 불신앙의 장벽 앞에서도 긍휼을 베푸시며, 제자들의 더딘 깨달음 속에서도 인내하시며 하나님 나라의 일을 이루어 가십니다.\n\n묵상 질문\n1. 내가 예수님을 ''너무 잘 안다''고 생각하여 오히려 그분의 역사를 제한하고 있지는 않나요?\n2. 헤롯처럼 양심의 소리를 들으면서도 끊어내지 못하는 죄의 영역은 무엇인가요?\n3. 어려움 속에서도 "안심하라 내니 두려워하지 말라" 하시는 주님의 음성을 들을 수 있는 영적 민감함이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-11', E'예수의 예루살렘 입성과 대결 (마가복음 7장)', E'마가복음 7장', E'바리새인들과 서기관들이 예루살렘에서 와서 예수님의 제자들이 손을 씻지 않고 음식을 먹는 모습을 문제 삼았습니다. 유대인들에게 정결례는 단순한 위생 문제가 아니라 장로들의 전통을 지키는 신앙적 행위였습니다. 그러나 예수님은 이사야의 예언을 인용하시며 그들의 신앙이 겉모습에만 치중하고 있음을 지적하셨습니다. "이 백성이 입술로는 나를 공경하되 마음은 내게서 멀도다"(막 7:6)라는 말씀은 형식적 경건의 허상을 드러냅니다.\n\n예수님은 고르반 전통을 예로 드시며 그들의 위선을 구체적으로 폭로하셨습니다. 하나님께 드림이 되었다는 명목으로 부모 봉양의 책임을 회피하는 것은, 하나님의 계명을 사람의 전통으로 무력화시키는 행위였습니다. 진정한 부정함은 씻지 않은 손에서 오는 것이 아니라 마음에서 나오는 악한 생각, 음란, 도둑질, 살인, 간음, 탐욕이라고 선언하셨습니다. 이는 외적 정결보다 내면의 성결이 하나님께서 원하시는 참된 경건임을 보여줍니다.\n\n이방 땅 두로로 가신 예수님은 수로보니게 여인을 만나십니다. 딸의 치유를 간구하는 이방 여인에게 예수님은 자녀의 떡을 개들에게 줄 수 없다고 말씀하셨지만, "상 아래 개들도 아이들이 먹던 부스러기를 먹나이다"라는 그녀의 겸손한 응답은 예수님의 마음을 움직였습니다. 장로의 전통을 철저히 지키면서도 마음이 하나님에게서 먼 바리새인들과, 이방인이면서도 예수님을 향한 간절한 믿음을 보인 이 여인의 대조는 우리에게 참된 신앙이 무엇인지 묻게 합니다.\n\n데가볼리 지방에서 예수님은 귀 먹고 말 더듬는 자를 고치셨습니다. 하늘을 우러러 탄식하시며 "에바다"라고 말씀하신 예수님의 모습에는 인간의 고통을 함께 아파하시는 긍휼이 담겨 있습니다. 사람들이 "그가 모든 것을 잘하였도다"라고 감탄한 것처럼, 예수님은 단지 기적을 행하신 것이 아니라 소외된 이들을 온전한 삶으로 회복시키셨습니다.', E'오늘의 핵심\n예수님은 형식적 종교 행위보다 마음의 성결을 원하시며, 진정한 경건은 하나님과 이웃을 향한 사랑에서 나타납니다.\n\n묵상 질문\n1. 내 신앙생활에서 형식은 지키지만 마음이 따르지 않는 영역은 무엇인가요?\n2. 수로보니게 여인처럼 겸손하게 은혜를 구하는 믿음이 내게 있나요?\n3. 예수님의 긍휼하심을 경험한 나는 소외된 이웃을 어떻게 대하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-12', E'예수의 예루살렘 입성과 대결 (마가복음 8장)', E'마가복음 8장', E'예수님께서 사천 명을 먹이신 기적은 단순한 이적 그 이상의 의미를 담고 있습니다. 사흘 동안 예수님과 함께한 무리를 향해 "내가 무리를 불쌍히 여기노라"고 말씀하시는 그분의 마음에는 깊은 긍휼이 담겨 있었습니다. 광야에서 떡 일곱 개와 작은 생선 몇 마리로 사천 명을 먹이신 후, 남은 조각이 일곱 광주리나 되었다는 기록은 하나님 나라의 풍성함을 보여줍니다.\n\n그런데 이 놀라운 기적을 목격한 직후, 바리새인들은 여전히 하늘로부터 오는 표적을 요구합니다. 예수님은 마음속으로 깊이 탄식하셨습니다. 눈앞에서 펼쳐진 하나님의 역사를 보고도 또 다른 증거를 요구하는 그들의 완고함 때문이었습니다. 예수님은 제자들에게 바리새인들의 누룩과 헤롯의 누룩을 주의하라고 경고하셨지만, 제자들조차 이 말씀을 떡이 없는 것에 대한 책망으로 오해합니다. 오천 명과 사천 명을 먹이신 기적을 경험하고도 여전히 물질적인 것에만 마음이 머물러 있었던 것입니다.\n\n벳새다에서 맹인을 고치실 때, 예수님은 두 번에 걸쳐 안수하셨습니다. 처음에는 "나무 같은 것들이 걸어 가는 것"으로 보이다가, 두 번째 안수 후에야 모든 것을 밝히 보게 되었습니다. 이것은 우리의 영적 눈이 열리는 과정도 점진적일 수 있음을 보여줍니다.\n\n빌립보 가이사랴에서 베드로는 "주는 그리스도시니이다"라는 위대한 고백을 합니다. 하지만 예수님이 고난과 죽음을 예고하시자, 같은 베드로가 예수님을 붙들고 항변합니다. 예수님은 그를 "사탄"이라고 부르시며 엄히 꾸짖으셨습니다. 하나님의 일을 생각하지 않고 사람의 일을 생각했기 때문입니다.\n\n"누구든지 나를 따라오려거든 자기를 부인하고 자기 십자가를 지고 나를 따를 것이니라"는 예수님의 부르심은 오늘 우리에게도 동일하게 주어집니다. 온 천하를 얻고도 목숨을 잃으면 무엇이 유익하겠습니까? 진정한 제자의 길은 자기 부인과 십자가를 지는 것, 그리고 복음을 위해 목숨까지도 내어놓는 헌신입니다.', E'오늘의 핵심\n예수님을 그리스도로 고백하는 것과 그분의 십자가의 길을 따르는 것은 분리될 수 없습니다. 참된 제자도는 자기를 부인하고 매일의 십자가를 지는 것입니다.\n\n묵상 질문\n1. 나는 영적인 것들을 얼마나 분명하게 보고 있나요? 아직도 흐릿하게 보이는 부분은 무엇인가요?\n2. 예수님을 따른다고 하면서도 여전히 내가 붙들고 있는 ''사람의 일''은 무엇일까요?\n3. 복음을 위해 기꺼이 포기할 수 있는 것과 아직 포기하기 어려운 것은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-13', E'예수의 예루살렘 입성과 대결 (마가복음 9장)', E'마가복음 9장', E'마가복음 9장은 예수님의 정체성에 대한 가장 극적인 계시로 시작됩니다. 높은 산에서 예수님의 옷이 세상의 어떤 빨래도 낼 수 없는 광채로 빛나고, 모세와 엘리야가 나타나 대화를 나눕니다. 하늘에서는 "이는 내 사랑하는 아들이니 너희는 그의 말을 들으라"는 음성이 울려 퍼집니다. 세례 때와 동일한 이 선언은 예수님이 율법(모세)과 예언(엘리야)의 성취자이시며, 이제 제자들이 들어야 할 유일한 권위임을 분명히 보여줍니다.\n\n그러나 산 아래로 내려오자 전혀 다른 현실이 펼쳐집니다. 제자들은 귀신 들린 아이를 고치지 못해 서기관들과 논쟁 중이었고, 아이의 아버지는 절박한 심정으로 예수님께 도움을 청합니다. "무엇을 하실 수 있거든 우리를 불쌍히 여기사 도와 주옵소서"라는 그의 간청에 예수님은 "믿는 자에게는 능히 하지 못할 일이 없느니라"고 응답하십니다. 이때 아버지의 절규가 우리 모두의 고백이 됩니다: "내가 믿나이다 나의 믿음 없는 것을 도와 주소서." 완전한 믿음이 아닌 불완전한 믿음이라도 정직하게 고백할 때, 예수님은 그 연약함을 품어주시고 역사하십니다.\n\n이어지는 장면들은 제자들의 영적 미성숙을 적나라하게 드러냅니다. 예수님이 십자가 죽음을 예고하시는 동안 그들은 누가 더 큰지를 다투고 있었습니다. 예수님은 어린아이를 품에 안으시며 섬김의 리더십을 가르치시고, 자기 그룹에 속하지 않은 사람의 사역을 인정하는 넓은 포용력을 보여주십니다. 마지막 부분의 강한 경고들은 공동체 안에서 연약한 자를 실족시키는 일의 심각성과, 죄와의 철저한 단절의 필요성을 일깨워줍니다.\n\n변화산의 영광과 일상의 연약함, 하늘의 음성과 땅의 신음, 믿음과 불신앙의 공존 - 이것이 우리 신앙의 현실입니다. 그 간극을 메우시는 분은 오직 예수님이십니다.', E'오늘의 핵심\n영광스러운 변화산의 체험과 연약한 일상의 현실 사이에서, 예수님은 불완전한 믿음도 품어주시며 제자들을 섬김의 길로 인도하십니다.\n\n묵상 질문\n1. "믿나이다 나의 믿음 없는 것을 도와 주소서"라는 고백이 내게 위로가 되는 이유는 무엇인가요?\n2. 영적 체험 후 일상으로 돌아왔을 때 무력감을 느낀 적이 있나요? 그때 필요한 것은 무엇일까요?\n3. 내가 은연중에 "우리 편"과 "남의 편"을 나누며 배타적이 되는 영역은 어디인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-14', E'예수의 예루살렘 입성과 대결 (마가복음 10장)', E'마가복음 10장', E'마가복음 10장은 예수님께서 예루살렘을 향해 가시는 길에서 만나신 사람들과 제자들에게 하나님 나라의 진정한 가치를 가르쳐주시는 장면들을 보여줍니다. 바리새인들은 이혼에 대한 율법적 허용을 묻지만, 예수님은 창조의 원리로 돌아가 결혼의 신성함을 일깨워 주십니다. 모세가 이혼 증서를 허락한 것은 사람들의 완악함 때문이었을 뿐, 하나님의 원래 뜻은 "둘이 한 몸"이 되는 것이었습니다.\n\n이어서 제자들이 어린아이들을 막자 예수님은 노하시며 "하나님의 나라가 이런 자의 것"이라고 선언하십니다. 어린아이처럼 의존적이고 겸손하게 받아들이는 자세가 하나님 나라에 들어가는 조건임을 가르치신 것입니다. 그런데 바로 다음에 등장하는 부자 청년은 정반대의 모습을 보여줍니다. 계명을 다 지켰다고 자부하면서도 재물을 포기하라는 말씀 앞에서는 근심하며 돌아갑니다. 예수님은 그를 사랑의 눈빛으로 바라보셨지만, 그는 영생보다 재물을 선택한 것입니다.\n\n"낙타가 바늘귀로 나가는 것이 부자가 하나님의 나라에 들어가는 것보다 쉬우니라"는 말씀에 제자들마저 놀랍니다. 그러나 예수님은 "하나님으로서는 다 하실 수 있느니라"고 희망을 주십니다. 구원은 인간의 노력이 아닌 하나님의 은혜로 가능함을 가르치신 것입니다.\n\n예루살렘으로 가시는 길에서 예수님은 자신의 고난과 죽음, 부활을 예고하십니다. 그런데 야고보와 요한은 영광의 자리를 요구합니다. 예수님의 고난 예고를 듣고도 권력을 탐하는 제자들의 모습은 우리의 연약함을 보여줍니다. 예수님은 "너희 중에 크고자 하는 자는 섬기는 자가 되라"고 가르치시며, 자신이 "섬김을 받으려 함이 아니라 도리어 섬기려" 오셨음을 분명히 하십니다.\n\n마지막으로 여리고의 맹인 바디매오는 "다윗의 자손 예수여"라고 부르짖습니다. 사람들이 막아도 더욱 크게 부르짖는 그의 간절함은 예수님을 멈추게 합니다. 겉옷을 벗어던지고 뛰어가는 그의 모습은 부자 청년과 극명한 대조를 이룹니다. 하나님 나라는 이렇게 모든 것을 포기하고서라도 예수님께 나아가는 자들의 것입니다.', E'오늘의 핵심\n예수님은 예루살렘으로 가시는 길에서 하나님 나라의 역설적 가치를 가르치십니다. 어린아이같은 겸손, 재물보다 중요한 영생, 섬김의 리더십이 그것입니다.\n\n묵상 질문\n1. 내가 하나님 나라보다 더 소중히 여기며 놓지 못하는 것은 무엇인가요?\n2. 섬기는 리더십을 실천하기 위해 내려놓아야 할 권위의식은 무엇일까요?\n3. 바디매오처럼 간절히 예수님을 부르짖어야 할 나의 필요는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-16', E'예수의 예루살렘 입성과 대결 (마가복음 11장)', E'마가복음 11장', E'예루살렘을 향한 예수님의 여정이 마침내 그 목적지에 도달합니다. 감람산에서 바라본 성전의 모습은 웅장했지만, 그 안에는 깊은 영적 타락이 자리하고 있었습니다. 예수님은 구약의 예언대로 나귀를 타고 입성하시는데, 이는 전쟁의 왕이 아닌 평화의 왕으로 오심을 보여줍니다. 백성들이 "호산나 다윗의 자손이여"라고 외치며 환영했지만, 그들의 기대와 예수님의 사명 사이에는 큰 간극이 있었습니다.\n\n다음 날 아침, 잎만 무성한 무화과나무를 저주하신 일은 단순한 감정 표출이 아니었습니다. 이스라엘을 상징하는 무화과나무처럼, 겉으로는 종교적 활동이 왕성했지만 참된 열매가 없는 당시 유대교의 실상을 드러내신 것입니다. 이어서 성전에 들어가신 예수님은 "만민이 기도하는 집"을 "강도의 소굴"로 만든 자들을 내쫓으십니다. 이방인의 뜰에서 벌어지는 상업 행위는 이방인들의 예배를 방해했고, 성전을 이용해 부당한 이익을 취하는 종교 지도자들의 탐욕을 보여주었습니다.\n\n종교 지도자들은 예수님께 "무슨 권위로 이런 일을 하느냐"고 따져 묻습니다. 그러나 이들은 진리를 구하는 것이 아니라 자신들의 기득권을 지키려 했을 뿐입니다. 예수님의 역질문 앞에서 "알지 못하겠다"고 답한 그들의 모습은, 백성의 여론만 의식하고 하나님의 뜻에는 무관심한 위선을 드러냅니다.\n\n마른 무화과나무를 보고 놀라는 제자들에게 예수님은 믿음의 기도에 대해 가르치십니다. 그러나 여기서 중요한 것은 "무엇이든 이루어진다"는 약속이 아니라, 하나님의 뜻에 합당한 기도와 용서하는 마음입니다. 성전을 정화하신 예수님이 곧이어 용서를 말씀하신 것은, 참된 예배는 하나님과의 관계뿐 아니라 이웃과의 관계 회복에서 시작됨을 보여줍니다.\n\n오늘 우리의 신앙생활도 잎만 무성한 무화과나무는 아닌지, 기도의 집이 장사하는 곳이 되어있지는 않은지 돌아봅시다. 예수님의 권위는 우리의 편안한 종교생활을 뒤흔들지만, 그것이 바로 참된 열매를 맺는 길입니다.', E'오늘의 핵심\n예수님은 평화의 왕으로 예루살렘에 입성하셔서 열매 없는 종교의 위선을 드러내시고, 성전이 모든 민족을 위한 기도의 집이 되기를 원하십니다.\n\n묵상 질문\n1. 내 신앙생활에서 잎만 무성하고 열매는 없는 영역은 무엇인가요?\n2. 하나님과의 관계에서 ''거래''나 ''장사''하는 마음은 없는지 점검해보셨나요?\n3. 용서하지 못하는 마음이 내 기도를 가로막고 있지는 않나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-17', E'예수의 예루살렘 입성과 대결 (마가복음 12장)', E'마가복음 12장', E'마가복음 12장은 예루살렘 성전에서 벌어진 긴장된 대결의 연속입니다. 포도원 농부의 비유로 시작되는 이 장면은 이스라엘 지도자들의 완악함을 적나라하게 드러냅니다. 주인이 보낸 종들을 때리고 죽이며, 마침내 사랑하는 아들까지 죽여버리는 농부들의 모습은 선지자들을 핍박하고 이제 하나님의 아들까지 거부하는 종교 지도자들의 실상을 보여줍니다. 예수님은 "건축자들이 버린 돌이 모퉁이의 머릿돌이 되었다"는 시편 말씀으로 하나님의 역설적인 구원 계획을 선포하셨습니다.\n\n이어지는 세금 논쟁과 부활 논쟁은 예수님을 함정에 빠뜨리려는 시도였지만, 오히려 그분의 지혜를 드러내는 계기가 되었습니다. "가이사의 것은 가이사에게, 하나님의 것은 하나님께"라는 말씀은 단순히 납세의 의무를 넘어, 하나님의 형상으로 지음받은 우리가 마땅히 하나님께 드려야 할 것이 무엇인지를 생각하게 합니다. 부활을 부인하는 사두개인들에게는 "하나님은 죽은 자의 하나님이 아니요 산 자의 하나님"이라는 선언으로 그들의 잘못된 성경 이해를 바로잡으셨습니다.\n\n한 서기관과의 대화에서는 율법의 핵심이 사랑임이 분명히 드러납니다. 하나님 사랑과 이웃 사랑이라는 두 계명이 모든 제사와 예물보다 중요하다는 서기관의 깨달음을 예수님은 기뻐하셨습니다. 그러나 같은 서기관들이 긴 옷을 입고 높은 자리를 탐하며 과부의 가산을 삼키는 위선적 모습도 신랄하게 지적하셨습니다.\n\n마지막 장면에서 가난한 과부가 넣은 두 렙돈은 부자들의 많은 헌금보다 더 큰 가치로 인정받았습니다. 그것은 그녀의 "생활비 전부"였기 때문입니다. 예수님은 액수가 아닌 헌신의 깊이를 보셨고, 남은 것에서가 아닌 전부를 드리는 믿음을 귀하게 여기셨습니다. 이는 곧 십자가에서 자신의 전부를 내어주실 예수님의 희생을 미리 보여주는 아름다운 본보기였습니다.', E'오늘의 핵심\n예루살렘 성전에서 종교 지도자들과 대결하시는 예수님은 그들의 위선을 드러내시고, 참된 신앙은 사랑과 헌신에 있음을 가르치십니다.\n\n묵상 질문\n1. 내가 하나님께서 보내신 메신저나 말씀을 거부하고 있는 영역은 없을까요?\n2. 하나님 사랑과 이웃 사랑이 내 신앙생활에서 실제로 최우선이 되고 있나요?\n3. 과부의 두 렙돈처럼 하나님께 온전히 드려야 할 나의 ''전부''는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-18', E'예수의 예루살렘 입성과 대결 (마가복음 13장)', E'마가복음 13장', E'성전의 화려함에 감탄하는 제자들에게 예수님은 충격적인 선언을 하십니다. "돌 하나도 돌 위에 남지 않고 다 무너뜨려지리라." 유대인들의 자부심이자 신앙의 중심이었던 예루살렘 성전이 완전히 파괴될 것이라는 말씀은, 제자들에게 세상이 무너지는 것과 같은 충격이었을 것입니다. 감람산에서 성전을 바라보시며 예수님은 앞으로 일어날 일들을 차근차근 설명하십니다. 거짓 그리스도의 등장, 전쟁과 지진, 그리고 제자들이 받을 박해까지. 그런데 주목할 것은 예수님이 이 모든 환난을 "재난의 시작"이라고 표현하신다는 점입니다. 마치 해산의 고통이 새 생명의 시작을 알리듯, 이 고난들은 하나님 나라의 완성을 향한 과정임을 암시합니다.\n\n특별히 예수님은 제자들이 공회와 회당에서 재판받고 매질당할 것을 예고하시면서도, 이것이 "증거가 되려 함이라"고 말씀하십니다. 박해받는 그 순간조차도 복음을 전하는 기회가 된다는 것입니다. 더 나아가 "말하는 이는 너희가 아니요 성령이시니라"는 약속을 주십니다. 가장 두렵고 막막한 순간에 성령께서 직접 말씀을 주신다는 이 약속은 얼마나 큰 위로가 되는지요. 예수님은 무화과나무의 비유를 통해 이런 징조들을 분별할 지혜를 주시면서도, 정작 그날과 그때는 "아버지만 아시느니라"고 하십니다. 우리가 알아야 할 것은 그 정확한 시기가 아니라, 언제든 주님을 맞을 준비를 하며 깨어 있는 삶입니다.\n\n"깨어 있으라"는 명령이 이 장에서 네 번이나 반복됩니다. 이는 단순히 잠들지 말라는 의미가 아니라, 영적으로 각성하여 주님의 뜻에 민감하게 반응하며 살라는 말씀입니다. 환난 중에도 복음은 만국에 전파되어야 하고, 끝까지 견디는 자는 구원을 받을 것입니다. 오늘도 우리는 주님의 재림을 기다리며, 맡겨진 사명에 충실한 종으로 살아갑니다.', E'오늘의 핵심\n예수님은 성전 파괴와 종말의 징조들을 예언하시면서, 환난 중에도 복음을 증거하며 깨어 있으라고 명하십니다.\n\n묵상 질문\n1. 내가 의지하고 있는 ''성전''과 같은 것들이 무너질 때, 나는 무엇을 붙잡습니까?\n2. 어려움과 박해 속에서도 복음을 증거할 수 있는 담대함은 어디서 올까요?\n3. ''깨어 있는 삶''이란 구체적으로 어떤 모습일까요? 오늘 내가 실천할 한 가지는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-19', E'최후의 만찬과 십자가 사역 (마가복음 1장)', E'마가복음 1장', E'마가복음은 시작부터 예수님이 누구신지를 강렬하게 보여줍니다. 이사야 선지자의 예언대로 광야에서 세례 요한이 나타나 "회개하고 죄 사함을 받으라"고 외칩니다. 온 유대와 예루살렘 사람들이 요단강으로 나아가 자기 죄를 자복하며 세례를 받는 놀라운 일이 일어났습니다. 그런데 요한은 자신보다 능력이 많으신 분이 오실 것을 선포하며, "나는 굽혀 그의 신발끈을 풀기도 감당하지 못하겠노라"고 고백합니다.\n\n드디어 예수님이 갈릴리 나사렛에서 오셔서 요한에게 세례를 받으십니다. 죄 없으신 분이 죄인들과 같은 자리에 서신 것입니다. 물에서 올라오시는 순간, 하늘이 갈라지고 성령이 비둘기같이 내려오며 "너는 내 사랑하는 아들이라 내가 너를 기뻐하노라"는 하늘의 음성이 들립니다. 하나님 아버지께서 아들의 정체성을 공개적으로 선언하신 것입니다.\n\n성령은 곧바로 예수님을 광야로 이끄셨고, 그곳에서 40일간 사탄의 시험을 받으셨습니다. 첫 아담이 에덴에서 실패했던 그 시험을 둘째 아담이신 예수님은 광야에서 이기셨습니다. 요한이 잡힌 후, 예수님은 갈릴리로 가셔서 "때가 찼고 하나님의 나라가 가까이 왔으니 회개하고 복음을 믿으라"고 선포하십니다.\n\n갈릴리 해변에서 어부들을 부르실 때, 시몬과 안드레, 야고보와 요한은 즉시 그물을 버리고 따랐습니다. 가버나움 회당에서 가르치실 때 사람들은 그 교훈에 놀랐는데, 서기관들과 달리 권위 있게 가르치셨기 때문입니다. 더러운 귀신조차 "당신은 하나님의 거룩한 자"라고 그분의 정체를 알아보았습니다. 예수님은 귀신을 쫓아내시고, 열병 든 시몬의 장모를 고치시고, 온 동네의 병자들을 치유하셨습니다.\n\n새벽 미명에 한적한 곳에서 기도하시는 예수님의 모습은 그분이 어디서 권위와 능력을 얻으시는지 보여줍니다. 나병환자가 "원하시면 저를 깨끗하게 하실 수 있나이다"라고 믿음으로 나아왔을 때, 예수님은 불쌍히 여기시고 손을 내밀어 만지시며 "내가 원하노니 깨끗함을 받으라"고 말씀하셨습니다. 부정하다고 여겨지는 나병환자를 만지신 것은 율법의 경계를 넘어 사랑과 긍휼을 보여주신 것입니다.', E'오늘의 핵심\n하나님의 아들이신 예수님이 세례를 받으시고 성령의 권능으로 하나님 나라의 복음을 선포하시며, 그 권위를 가르침과 치유를 통해 나타내십니다.\n\n묵상 질문\n1. 예수님이 죄 없으신 분임에도 세례를 받으신 이유는 무엇일까요?\n2. 제자들이 즉시 그물을 버리고 따를 수 있었던 것은 무엇 때문일까요?\n3. 새벽 기도하시는 예수님의 모습이 내 기도 생활에 주는 도전은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-20', E'최후의 만찬과 십자가 사역 (마가복음 2장)', E'마가복음 2장', E'가버나움의 한 집이 사람들로 가득 찼습니다. 예수님의 소문을 듣고 몰려든 군중 때문에 문 앞까지 빽빽이 들어차 더 이상 들어설 자리가 없었습니다. 바로 그때, 네 사람이 중풍병자를 메고 왔지만 도저히 예수님께 다가갈 수 없자 놀라운 결단을 내립니다. 지붕을 뜯고 구멍을 낸 후 병자를 달아 내린 것입니다. 예수님은 그들의 믿음을 보시고 중풍병자에게 "네 죄 사함을 받았느니라"고 선언하십니다.\n\n이 선언은 즉시 논란을 일으킵니다. 서기관들은 마음속으로 "오직 하나님만이 죄를 사하실 수 있는데, 이 사람이 어찌 감히"라고 생각했습니다. 예수님은 그들의 생각을 아시고 질문으로 답하십니다. "네 죄 사함을 받았느니라 하는 말과 일어나 걸어가라 하는 말 중 어느 것이 쉽겠느냐?" 그리고는 중풍병자를 일으켜 세우심으로써 죄를 사하는 권세가 자신에게 있음을 증명하십니다.\n\n이어서 예수님은 세리 레위를 제자로 부르시고, 세리와 죄인들과 함께 식사하십니다. 바리새인들이 이를 비난하자 예수님은 "건강한 자에게는 의사가 쓸 데 없고 병든 자에게라야 쓸 데 있느니라"고 답하십니다. 금식 논쟁에서는 새 포도주와 새 부대의 비유로 새로운 시대가 왔음을 선언하시고, 안식일 논쟁에서는 "안식일이 사람을 위하여 있는 것"이라며 율법의 참된 정신을 가르치십니다.\n\n마가복음 2장은 예수님의 권위가 기존 종교 체계와 정면으로 충돌하는 장면들을 보여줍니다. 죄 사함의 권세, 죄인과 함께하는 사랑, 새로운 시대의 선포, 안식일의 주인 되심 - 이 모든 것이 당시 종교 지도자들에게는 용납할 수 없는 도전이었습니다. 그러나 예수님은 하나님 나라의 새로운 질서를 선포하시며, 율법의 형식이 아닌 사랑과 자비의 정신으로 사람들을 회복시키십니다. 지붕을 뚫고서라도 예수님께 나아간 네 친구의 믿음처럼, 우리도 어떤 장애물이 있더라도 주님께 나아가는 담대한 믿음이 필요합니다.', E'오늘의 핵심\n예수님은 죄를 사하시고 병든 자를 고치시며 율법의 참된 의미를 가르치심으로써, 하나님 나라의 새로운 권위를 나타내십니다.\n\n묵상 질문\n1. 중풍병자를 예수님께 데려가기 위해 지붕을 뜯은 네 친구처럼, 나는 믿음의 장애물 앞에서 어떤 결단을 내리고 있나요?\n2. 예수님이 세리와 죄인들과 함께 식사하신 것처럼, 내가 품어야 할 소외된 이웃은 누구인가요?\n3. 종교적 형식과 진정한 사랑 사이에서 나는 무엇을 더 중요하게 여기고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-21', E'최후의 만찬과 십자가 사역 (마가복음 3장)', E'마가복음 3장', E'안식일에 회당에서 일어난 일은 예수님의 사역이 가져올 충돌을 분명히 보여줍니다. 손 마른 사람을 고치시는 예수님께 종교 지도자들은 율법 위반을 찾으려 했지만, 예수님은 그들에게 본질적인 질문을 던지셨습니다. "안식일에 선을 행하는 것과 악을 행하는 것, 생명을 구하는 것과 죽이는 것, 어느 것이 옳으냐"(막 3:4). 침묵으로 답한 그들의 완악함은 종교적 형식이 하나님의 긍휼을 가로막는 비극을 드러냅니다.\n\n예수님의 치유 사역이 널리 알려지자 갈릴리뿐 아니라 유대, 예루살렘, 이두매, 요단 강 건너편, 두로와 시돈에서까지 수많은 무리가 몰려들었습니다. 병든 자들이 예수님을 만지려 몰려드는 가운데, 예수님은 산으로 올라가 열두 제자를 부르셨습니다. 이들을 세우신 목적은 분명했습니다. 함께 있게 하시고, 전도하게 하시며, 귀신을 내쫓는 권능을 주시려는 것이었습니다. 하나님 나라의 일은 처음부터 공동체를 통해 이루어지도록 계획되었음을 보여줍니다.\n\n그러나 예수님의 사역은 오해와 비방에 직면했습니다. 친족들조차 그가 미쳤다고 여겼고, 서기관들은 귀신의 왕 바알세불을 힘입어 귀신을 쫓아낸다고 모함했습니다. 이에 예수님은 분열된 나라와 집의 비유로 그들의 논리가 얼마나 모순적인지 지적하셨습니다. 더 나아가 성령을 모독하는 죄의 심각성을 경고하시며, 하나님의 일을 사탄의 일로 왜곡하는 영적 맹목의 위험을 드러내셨습니다.\n\n마가복음 3장의 마지막은 혈연을 넘어선 새로운 가족 개념을 제시합니다. 예수님의 어머니와 형제들이 밖에서 찾을 때, 예수님은 둘러앉은 무리를 가리키며 "누구든지 하나님의 뜻대로 행하는 자가 내 형제요 자매요 어머니이니라"고 선언하셨습니다. 하나님 나라의 가족은 혈통이 아닌 순종으로 맺어진다는 혁명적 가르침입니다.', E'오늘의 핵심\n예수님은 종교적 형식주의와 충돌하시며 생명을 살리는 하나님의 긍휼을 보여주시고, 열두 제자를 세워 하나님 나라 사역의 공동체적 성격을 드러내셨습니다.\n\n묵상 질문\n1. 내가 붙잡고 있는 종교적 형식이 하나님의 사랑과 긍휼을 가로막고 있지는 않나요?\n2. 예수님께서 나를 부르셔서 함께하기 원하시는 공동체와 사역은 무엇일까요?\n3. 혈연과 관계를 넘어 하나님의 뜻을 행하는 영적 가족을 어떻게 이루어갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-23', E'최후의 만찬과 십자가 사역 (마가복음 4장)', E'마가복음 4장', E'예수님께서 갈릴리 바닷가에서 가르치실 때, 너무나 많은 무리가 몰려들어 예수님은 배에 올라앉으셨습니다. 바다 위의 배는 천연의 강단이 되었고, 사람들은 해변가에서 그 말씀에 귀를 기울였습니다. 이날 예수님이 들려주신 씨 뿌리는 자의 비유는 하나님 나라의 비밀을 담고 있었습니다.\n\n같은 씨앗이 네 가지 다른 땅에 떨어집니다. 길가, 돌밭, 가시떨기, 그리고 좋은 땅. 예수님은 이 비유를 통해 하나님의 말씀을 받아들이는 우리 마음의 상태를 보여주십니다. 길가와 같이 굳어진 마음에는 말씀이 뿌리를 내리지 못하고, 돌밭 같은 얕은 마음은 시련이 오면 쉽게 포기합니다. 가시떨기처럼 세상 염려와 재물의 유혹으로 가득한 마음은 말씀이 자라나지 못하게 막습니다. 그러나 좋은 땅과 같은 마음은 놀라운 결실을 맺습니다.\n\n예수님은 계속해서 하나님 나라의 신비를 비유로 가르치십니다. 등불은 감추어지기 위해서가 아니라 빛을 비추기 위해 존재하듯이, 하나님 나라의 진리도 결국 드러나게 됩니다. 또한 씨앗이 땅 속에서 신비롭게 자라나듯이, 하나님 나라는 우리가 이해할 수 없는 방식으로 성장합니다. 작은 겨자씨가 큰 나무가 되어 새들이 깃들듯이, 하나님 나라는 미미하게 시작되지만 놀랍게 확장됩니다.\n\n그날 저녁, 예수님은 지친 몸으로 제자들과 함께 배를 타고 갈릴리 호수를 건너가십니다. 하루 종일 가르치신 피로 때문에 배 고물에서 깊이 잠드신 예수님. 그때 큰 광풍이 일어나 배가 물로 가득 차게 됩니다. 제자들은 공포에 사로잡혀 예수님을 깨웁니다. 일어나신 예수님이 바람과 바다를 꾸짖으시자 놀랍게도 모든 것이 잔잔해집니다. 제자들은 "그가 누구이기에 바람과 바다도 순종하는가" 하며 경외감에 사로잡힙니다.\n\n이 하루의 사건들은 예수님이 누구신지를 점진적으로 드러냅니다. 하나님 나라의 비밀을 아시는 분, 자연만물을 다스리시는 분, 그러면서도 우리와 같이 피곤함을 느끼시는 분. 예수님은 하나님의 아들이시면서 동시에 우리와 함께하시는 임마누엘이십니다.', E'오늘의 핵심\n예수님은 비유를 통해 하나님 나라의 비밀을 가르치시고, 풍랑을 잔잔케 하심으로 자연을 다스리시는 하나님의 아들임을 나타내셨습니다.\n\n묵상 질문\n1. 내 마음은 어떤 땅과 같은지, 말씀의 씨앗이 잘 자라날 수 있는 마음인지 돌아봅시다.\n2. 인생의 풍랑 속에서도 평안히 쉬시는 예수님을 신뢰하고 있나요?\n3. 작은 겨자씨처럼 시작되는 하나님 나라의 일에 나는 어떻게 동참하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-24', E'최후의 만찬과 십자가 사역 (마가복음 5장)', E'마가복음 5장', E'거라사 지방에 도착하신 예수님을 가장 먼저 맞이한 것은 무덤 사이에서 살던 한 사람이었습니다. 그는 더러운 귀신에게 사로잡혀 쇠사슬도 끊어버릴 만큼 광포했고, 밤낮 소리 지르며 돌로 자기 몸을 해치고 있었습니다. 사회로부터 완전히 격리되어 죽은 자들의 거처에서 살아가는 이 사람의 모습은 죄와 어둠의 권세 아래 있는 인간의 처참한 상태를 보여줍니다.\n\n예수님께서 귀신에게 "그 사람에게서 나오라" 명하시자, 귀신들은 돼지 떼로 들어가기를 간청합니다. 이천 마리나 되는 돼지들이 바다에 빠져 죽는 엄청난 손실이 발생했지만, 예수님께는 한 영혼의 회복이 그 무엇보다 소중했습니다. 정신이 온전해진 그 사람은 예수님과 함께 있기를 원했으나, 주님은 오히려 그를 가족에게 돌려보내며 하나님의 큰 일을 전파하는 증인으로 세우십니다.\n\n바다를 건너 돌아오신 예수님께는 또 다른 간절함이 기다리고 있었습니다. 회당장 야이로의 죽어가는 딸, 그리고 12년간 혈루증으로 고통받던 여인이었습니다. 여인은 모든 재산을 의사들에게 써버렸지만 오히려 병세가 악화되었고, 율법적으로 부정한 자가 되어 공동체에서 격리된 채 살아왔습니다. 그러나 예수님의 옷자락만 만져도 나을 것이라는 믿음으로 무리 속에서 손을 뻗었을 때, 즉시 병의 근원이 마르는 치유를 경험합니다.\n\n예수님은 단순히 육체의 치유만이 아니라 "딸아, 네 믿음이 너를 구원하였으니 평안히 가라"는 축복으로 그녀를 온전한 하나님의 자녀로 회복시켜 주셨습니다. 야이로의 딸이 죽었다는 소식에도 "두려워하지 말고 믿기만 하라"고 하신 예수님은 죽음의 권세까지도 다스리시는 생명의 주님이심을 보여주셨습니다. "달리다굼"(소녀야 일어나라)이라는 한 마디에 죽은 소녀가 일어나 걸었습니다.\n\n이 모든 사건들은 예수님이 어떤 분이신지를 선명하게 드러냅니다. 귀신의 권세를 제압하시고, 불치병을 치유하시며, 죽음까지도 생명으로 바꾸시는 분. 그분은 사회에서 버림받고 소외된 한 영혼을 찾아 풍랑을 뚫고 오시는 목자이시며, 절망 속에서도 믿음으로 손 뻗는 이들에게 구원과 평안을 주시는 구원자이십니다.', E'오늘의 핵심\n예수님은 귀신의 권세, 질병, 죽음을 다스리시는 생명의 주님으로서, 가장 소외되고 절망적인 상황에 있는 이들을 찾아가 온전한 회복과 구원을 베푸십니다.\n\n묵상 질문\n1. 무덤 사이에서 살던 사람처럼 나를 묶고 있는 영적인 사슬은 무엇인가요?\n2. 12년 된 혈루증 여인의 믿음처럼, 절망적 상황에서도 예수님께 손 뻗을 수 있는 믿음이 내게 있나요?\n3. 예수님께서 "두려워하지 말고 믿기만 하라"고 말씀하신다면, 오늘 내가 믿음으로 극복해야 할 두려움은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-25', E'최후의 만찬과 십자가 사역 (마가복음 6장)', E'마가복음 6장', E'예수님께서 고향 나사렛으로 가셨을 때, 안식일에 회당에서 가르치시자 사람들은 놀랐습니다. 그러나 그들의 놀라움은 곧 배척으로 바뀝니다. "이 사람이 마리아의 아들 목수가 아니냐"라며 예수님을 거부한 것입니다. 너무나 잘 아는 사람이라는 선입견이 하나님의 아들을 알아보지 못하게 한 것입니다. 마가는 예수님께서 그곳에서는 소수의 병자만 고치실 수 있었고, 사람들의 불신을 이상히 여기셨다고 기록합니다.\n\n이어서 예수님은 열두 제자를 둘씩 짝지어 파송하십니다. 더러운 귀신을 제어하는 권능을 주시면서도, 여행을 위해 지팡이 외에는 아무것도 가지지 말라고 명하십니다. 이는 전적으로 하나님의 공급하심을 의지하며 복음 전파에만 집중하라는 뜻이었습니다. 제자들은 순종하여 나가 회개를 전파하고 많은 귀신을 쫓아내며 병자들을 고쳤습니다.\n\n한편 헤롯은 예수님의 소문을 듣고 세례 요한이 살아났다고 두려워합니다. 마가는 여기서 세례 요한의 죽음을 상세히 기록하는데, 헤롯의 생일 잔치에서 헤로디아의 딸이 춤을 추고 그 대가로 요한의 머리를 요구하는 끔찍한 장면이 펼쳐집니다. 의로운 자의 죽음과 권력자의 타락이 대비되며, 예수님을 따르는 길이 결코 쉽지 않음을 보여줍니다.\n\n파송받았던 제자들이 돌아와 보고할 때, 예수님은 그들을 한적한 곳으로 데려가 쉬게 하려 하셨습니다. 그러나 무리가 먼저 그곳에 도착했고, 예수님은 목자 없는 양 같은 그들을 불쌍히 여기사 가르치셨습니다. 저녁이 되어 제자들이 무리를 보내자고 하지만, 예수님은 "너희가 먹을 것을 주라"고 하십니다. 떡 다섯 개와 물고기 두 마리로 오천 명을 먹이신 이 표적은 하나님의 풍성한 공급하심을 보여줍니다.\n\n밤이 되어 제자들이 바다에서 역풍을 만나 고생할 때, 예수님은 물 위를 걸어 그들에게 오십니다. 제자들은 유령인가 하여 두려워했지만, "안심하라 내니 두려워하지 말라"는 예수님의 음성에 평안을 얻습니다. 마가는 제자들이 떡 떼시던 일을 깨닫지 못하고 마음이 둔하여졌다고 지적하는데, 이는 표적을 보고도 예수님이 누구신지 온전히 깨닫지 못하는 우리의 모습을 보여줍니다.', E'오늘의 핵심\n예수님은 고향에서 배척받으셨지만 제자들을 파송하여 복음을 전하게 하셨고, 목자 없는 양 같은 무리를 불쌍히 여기사 가르치시고 먹이시며, 풍랑 속에서도 제자들과 함께하셨습니다.\n\n묵상 질문\n1. 나도 너무 익숙하다는 이유로 예수님의 역사를 제한하고 있지는 않나요?\n2. 예수님께서 "너희가 먹을 것을 주라"고 하실 때, 내가 가진 작은 것은 무엇인가요?\n3. 인생의 풍랑 속에서 "안심하라 내니"라고 말씀하시는 주님의 음성을 듣고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-26', E'교회를 위한 권면 (고린도전서 5장)', E'고린도전서 5장', E'고린도 교회에 충격적인 소식이 전해졌습니다. 어떤 성도가 자신의 계모와 부정한 관계를 맺고 있다는 것이었습니다. 이러한 음행은 당시 이방인들 사이에서도 용납되지 않는 수준의 심각한 죄였습니다. 더욱 놀라운 것은 고린도 교회가 이 문제에 대해 아무런 조치도 취하지 않고 오히려 자신들의 영적 은사와 지식을 자랑하며 교만해하고 있었다는 사실입니다.\n\n바울은 이런 상황을 듣고 단호하게 대처합니다. 비록 몸은 멀리 떨어져 있었지만 영으로는 함께 있는 것처럼, 그는 이미 그 악행을 행한 자에 대한 판단을 내렸다고 선언합니다. 바울이 제시한 해결책은 "이런 자를 사탄에게 내주었으니 이는 육신은 멸하고 영은 주 예수의 날에 구원을 받게 하려 함이라"(고전 5:5)는 것이었습니다. 이는 교회로부터의 축출을 의미하는 동시에, 궁극적으로는 그의 영혼이 회개하여 구원받기를 바라는 사랑의 징계였습니다.\n\n바울은 적은 누룩이 온 덩어리에 퍼지는 원리를 들어 공동체의 순결함을 강조합니다. 그리스도께서 우리의 유월절 양이 되셔서 희생되신 것처럼, 교회는 묵은 누룩을 제거하고 순전함과 진실함의 떡으로 새로운 공동체가 되어야 한다고 가르칩니다. \n\n동시에 바울은 교회의 거룩함에 대한 균형 잡힌 관점을 제시합니다. 세상에서 죄인들과 완전히 단절하며 살 수는 없지만, 형제라고 불리는 사람이 지속적으로 죄 가운데 행하면서도 회개하지 않는다면 그와는 교제를 끊어야 한다고 명확히 가르칩니다. 교회는 세상 사람들을 판단하는 것이 아니라 교회 안에 있는 사람들의 거룩한 삶을 돌보는 책임이 있다는 것입니다.', E'오늘의 핵심\n교회의 거룩함은 타협할 수 없는 가치이며, 사랑의 징계를 통해 공동체 전체와 개인의 영적 건강을 지켜내야 합니다.\n\n묵상 질문\n1. 내가 속한 공동체에서 죄에 대해 침묵하거나 방관하고 있는 부분은 없나요?\n2. 사랑의 징계와 정죄의 차이를 분별하며 형제를 대하고 있나요?\n3. 나의 삶에서 제거해야 할 ''묵은 누룩''은 무엇인지 성령님께 여쭤보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-27', E'교회를 위한 권면 (고린도전서 6장)', E'고린도전서 6장', E'고린도 교회에 일어난 충격적인 소식이 바울의 귀에 들려왔습니다. 그리스도인들끼리의 분쟁을 교회 안에서 해결하지 못하고 세상 법정으로 가져가고 있다는 것이었습니다. 바울은 이러한 현실을 안타까워하며 "너희가 피차 고발함으로 너희 가운데 이미 뚜렷한 허물이 있나니 차라리 불의를 당하는 것이 낫지 아니하며 차라리 속는 것이 낫지 아니하냐"(고전 6:7)고 책망합니다.\n\n바울이 이토록 강하게 질책한 이유는 성도의 정체성과 관련이 있습니다. 그리스도인들은 장차 세상과 천사까지도 판단할 영적 권위를 부여받은 존재들입니다. 그런데 그들이 형제간의 작은 문제조차 스스로 해결하지 못하고 믿지 않는 자들 앞에서 서로를 고발한다는 것은 교회의 거룩한 증거를 무너뜨리는 일이었습니다. 바울은 교회 안에 지혜로운 중재자를 세워 갈등을 해결하라고 권면합니다.\n\n더 나아가 바울은 고린도 교인들이 과거의 죄악된 삶에서 벗어나 그리스도 안에서 새로운 존재가 되었음을 상기시킵니다. 음행, 우상숭배, 도적질과 같은 옛 삶의 모습들은 이제 그리스도의 이름과 성령 안에서 씻음받고 거룩하게 되었습니다. 특히 바울은 성도의 몸이 성령의 전임을 강조하며, 음행을 비롯한 모든 육체적 죄악을 경계합니다.\n\n"너희 몸은 너희가 하나님께로부터 받은 바 너희 가운데 계신 성령의 전"이라는 선언은 고린도 교인들에게 새로운 자기 이해를 제공합니다. 그들의 몸은 더 이상 자기 것이 아니라 그리스도의 피로 값을 치르고 산 하나님의 소유입니다. 따라서 몸으로 하나님께 영광을 돌려야 한다는 것이 바울의 결론입니다. 이는 단순히 도덕적 교훈을 넘어, 구원받은 성도의 정체성에서 비롯되는 거룩한 삶의 원리를 제시하고 있습니다.', E'오늘의 핵심\n바울은 성령의 전이 된 그리스도인들이 서로 사랑으로 문제를 해결하고, 거룩한 몸으로 하나님께 영광을 돌리는 삶을 살아야 함을 가르칩니다.\n\n묵상 질문\n1. 교회 안의 갈등을 세상 방식이 아닌 그리스도의 사랑으로 해결하고 있나요?\n2. 내 몸이 성령의 전이라는 진리가 일상의 선택에 어떤 영향을 주고 있나요?\n3. 과거의 죄악된 모습에서 씻음받은 은혜를 기억하며 감사하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-28', E'교회를 위한 권면 (고린도전서 7장)', E'고린도전서 7장', E'고린도 교회는 결혼과 독신에 관한 실제적인 문제들로 혼란을 겪고 있었습니다. 바울은 이들이 보낸 편지에 답하면서 결혼과 독신, 그리고 신앙생활의 관계에 대해 균형 잡힌 가르침을 제시합니다. 바울은 독신의 삶이 주님을 온전히 섬기는 데 유익하다고 권하면서도, 결혼 역시 하나님이 주신 선물임을 분명히 합니다. "만일 절제할 수 없거든 결혼하라 정욕이 불 같이 타는 것보다 결혼하는 것이 나으니라"(고전 7:9)는 말씀은 인간의 연약함을 이해하시는 하나님의 은혜를 보여줍니다.\n\n특별히 바울은 결혼한 부부들에게 서로의 몸에 대한 권리와 의무를 가르치며, 영적인 일과 육체적인 관계가 대립하는 것이 아니라 조화를 이루어야 함을 강조합니다. 또한 믿지 않는 배우자를 둔 신자들에게는 함부로 이혼하지 말고 오히려 그들을 통해 가정이 거룩해질 수 있음을 가르칩니다. 이는 하나님의 구원의 은혜가 가정 공동체를 통해서도 역사하심을 보여주는 것입니다.\n\n바울은 각 사람이 부르심을 받은 그 자리에서 하나님과 함께 거하라고 권면합니다. 종이든 자유인이든, 할례자든 무할례자든, 결혼했든 독신이든 그것이 중요한 것이 아니라 하나님의 계명을 지키며 그분과 동행하는 삶이 중요하다는 것입니다. 임박한 환난의 때를 의식하며 바울은 세상의 외형은 지나가는 것이니 영원한 것에 마음을 두라고 가르칩니다. 결국 결혼이든 독신이든 모든 삶의 목적은 주님을 온전히 섬기는 데 있음을 일깨워줍니다.', E'오늘의 핵심\n바울은 결혼과 독신 모두 하나님이 주신 은사이며, 어떤 상태에 있든지 그 자리에서 온전히 하나님을 섬기는 것이 가장 중요함을 가르칩니다.\n\n묵상 질문\n1. 나의 현재 삶의 자리(결혼, 독신, 직업 등)에서 하나님과 함께 거하고 있나요?\n2. 영적인 일과 일상의 삶을 분리하지 않고 조화롭게 살아가고 있나요?\n3. 세상의 외형이 아닌 영원한 가치를 추구하며 살아가도록 기도하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-04-30', E'교회를 위한 권면 (고린도전서 8장)', E'고린도전서 8장', E'고린도 교회에는 우상의 제물을 먹는 문제로 인한 갈등이 있었습니다. 당시 고린도는 이방 신전들이 즐비한 도시였고, 시장에서 판매되는 고기 대부분이 신전에 바쳐진 제물이었습니다. 이런 상황에서 그리스도인들이 어떻게 행동해야 할지는 실제적이고 절박한 문제였습니다.\n\n바울은 먼저 지식과 사랑의 차이를 분명히 구분합니다. 우상은 실제로 아무것도 아니며 오직 한 분 하나님만이 참 신이라는 지식은 옳은 것입니다. 그러나 바울은 "지식은 교만하게 하며 사랑은 덕을 세우나니"(고전 8:1)라고 말씀하면서, 지식만으로는 공동체를 세울 수 없음을 지적합니다. 진정한 앎은 하나님을 사랑하는 것에서 시작되며, 하나님께서도 그런 사람을 알아주신다고 바울은 가르칩니다.\n\n문제는 모든 사람이 이러한 지식을 가지고 있지 않다는 데 있었습니다. 오랫동안 우상 숭배 문화 속에서 살아온 일부 성도들은 여전히 우상의 제물에 대한 두려움과 거리낌을 가지고 있었습니다. 그들이 우상의 제물을 먹으면 양심이 더러워진다고 느꼈던 것입니다. 바울은 음식 자체가 우리를 하나님 앞에서 더 나은 사람으로 만들거나 못한 사람으로 만들지 않는다고 분명히 말합니다. 그러나 동시에 지식 있는 자의 자유로운 행동이 믿음이 약한 형제를 실족시킬 수 있음을 경고합니다.\n\n바울의 결론은 단호합니다. 그리스도께서 죽으심으로 구원하신 형제를 자신의 지식으로 멸망시키는 것은 곧 그리스도께 죄를 짓는 것이라고 선언합니다. 그래서 바울은 자신의 음식이 형제를 실족시킨다면 영원히 고기를 먹지 않겠다는 극단적인 사랑의 결단을 보여줍니다. 이것이 바로 지식을 넘어선 사랑의 실천이며, 그리스도의 몸 된 교회를 세워가는 진정한 지혜입니다.', E'오늘의 핵심\n바울은 우상의 제물 문제를 통해 지식보다 사랑이 우선되어야 함을 가르치며, 연약한 형제를 위해 자신의 자유를 기꺼이 포기하는 것이 그리스도인의 성숙한 자세임을 보여줍니다.\n\n묵상 질문\n1. 내가 가진 신앙의 지식이 다른 사람을 세우기보다 교만하게 만든 적은 없었나요?\n2. 연약한 형제자매를 위해 나의 자유와 권리를 포기할 수 있는 사랑이 내게 있나요?\n3. 오늘 하루 누군가를 배려하고 섬길 수 있는 구체적인 실천은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-01', E'예수의 치유와 가르침 (누가복음 6장)', E'누가복음 6장', E'안식일 논쟁을 통해 예수님께서 보여주신 것은 단순한 율법 해석의 차이가 아니었습니다. 밀 이삭을 잘라 먹는 제자들을 비난하는 바리새인들에게 예수님은 다윗의 예를 들어 응답하십니다. 생명을 유지하기 위한 필요가 율법의 형식보다 우선한다는 것입니다. 이어지는 회당에서의 장면은 더욱 극명합니다. 손 마른 사람을 고치시려는 예수님을 고발 거리로 삼으려는 종교 지도자들의 모습은, 그들이 얼마나 율법의 본질에서 멀어졌는지를 보여줍니다. "안식일에 선을 행하는 것과 악을 행하는 것, 생명을 구하는 것과 죽이는 것, 어느 것이 옳으냐"(눅 6:9)는 예수님의 질문은 안식일의 참된 의미를 일깨웁니다.\n\n이런 대립 속에서 예수님은 밤새도록 기도하신 후 열두 제자를 택하십니다. 세상의 기준으로는 부족한 사람들이었지만, 하나님 나라의 일꾼으로 부르심을 받은 것입니다. 평지에서 선포되는 예수님의 가르침은 더욱 혁명적입니다. 가난한 자, 주린 자, 우는 자가 복이 있다는 선언은 당시의 통념을 완전히 뒤집는 것이었습니다. 부요하고 배부르며 웃는 자들에게 화를 선언하시는 것은, 스스로 충족하여 하나님을 필요로 하지 않는 삶에 대한 경고였습니다.\n\n특별히 원수 사랑의 가르침은 하나님 나라의 급진적 성격을 보여줍니다. 미워하는 자를 선대하고, 저주하는 자를 축복하며, 모욕하는 자를 위해 기도하라는 명령은 인간의 본성을 거스르는 것입니다. 그러나 이것이 바로 "지극히 높으신 이의 아들"이 되는 길이라고 예수님은 말씀하십니다. 하나님께서 은혜를 모르는 자와 악한 자에게도 인자하신 것처럼, 우리도 그런 자비를 베풀어야 한다는 것입니다.\n\n예수님의 마지막 비유는 이 모든 가르침의 핵심을 담고 있습니다. 말씀을 듣고 행하는 것과 듣기만 하고 행하지 않는 것의 차이는, 반석 위에 집을 짓는 것과 모래 위에 짓는 것만큼 극명합니다. 종교 지도자들처럼 율법을 알면서도 그 정신을 놓치는 것이 아니라, 예수님의 말씀을 듣고 실천하는 삶이 참된 제자의 길입니다.', E'오늘의 핵심\n예수님은 율법의 형식이 아닌 생명과 사랑의 정신을 회복하시며, 세상의 가치관을 뒤집는 하나님 나라의 새로운 질서를 선포하십니다.\n\n묵상 질문\n1. 내가 신앙의 형식에 매여 정작 생명을 살리는 일을 놓치고 있는 부분은 없나요?\n2. 예수님께서 말씀하신 ''원수 사랑''을 오늘 내 일상에서 어떻게 실천할 수 있을까요?\n3. 말씀을 듣기만 하고 행하지 않는 영역이 있다면, 무엇이 나를 막고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-02', E'예수의 치유와 가르침 (누가복음 7장)', E'누가복음 7장', E'누가복음 7장은 예수님께서 가버나움에서 시작하여 여러 곳을 다니시며 하나님 나라의 놀라운 은혜를 보여주시는 장면들을 담고 있습니다.\n\n먼저 로마 백부장의 이야기가 우리의 시선을 사로잡습니다. 그는 이방인이었지만 유대인들로부터 존경받는 사람이었고, 병든 종을 위해 예수님께 도움을 청합니다. 놀라운 것은 그가 예수님께 직접 오시지 말아달라고 전하며 "말씀만 하사 내 하인을 낫게 하소서"라고 고백한 점입니다. 군인으로서 명령 체계를 잘 아는 그는 예수님의 말씀의 권위를 온전히 신뢰했습니다. 예수님은 이스라엘 중에서도 이만한 믿음을 만나보지 못하셨다고 감탄하셨습니다.\n\n나인 성문에서의 일은 더욱 극적입니다. 외아들을 잃은 과부가 장례 행렬과 함께 나오고 있었습니다. 그녀는 아무것도 요청하지 않았고, 예수님을 알지도 못했을 것입니다. 그러나 예수님은 그녀를 보시고 "불쌍히 여기사" 먼저 다가가셨습니다. 관에 손을 대시고 죽은 청년에게 "일어나라" 명하시니 그가 살아났습니다. 하나님의 긍휼은 우리가 구하기도 전에 먼저 찾아오는 은혜입니다.\n\n이어서 옥중의 세례 요한이 제자들을 통해 묻습니다. "오실 그이가 당신이오니이까?" 예수님은 직접적인 대답 대신 그들이 보고 들은 것을 전하라고 하십니다. 맹인이 보고, 못 걷는 사람이 걸으며, 죽은 자가 살아나고, 가난한 자에게 복음이 전파되는 것 - 이것이 바로 메시아 시대의 증거였습니다.\n\n마지막으로 바리새인 시몬의 집에서 일어난 일은 용서받은 자의 사랑을 보여줍니다. 죄인으로 알려진 한 여인이 눈물로 예수님의 발을 적시고 향유를 붓습니다. 시몬은 속으로 비판했지만, 예수님은 빚 탕감의 비유를 통해 가르치십니다. 많이 용서받은 자가 많이 사랑한다고. 그 여인의 행동은 용서받은 감격의 표현이었습니다.\n\n이 네 장면 모두에서 예수님은 세상의 기준과 다른 하나님 나라의 질서를 보여주십니다. 이방인의 믿음을 칭찬하시고, 과부의 슬픔에 먼저 다가가시며, 의심하는 자에게도 증거를 주시고, 죄인의 사랑을 받아주십니다. 하나님 나라는 자격 있는 자의 것이 아니라 은혜가 필요한 모든 이에게 열려 있는 나라임을 보여주십니다.', E'오늘의 핵심\n예수님은 이방인과 과부와 죄인을 포함한 모든 사람에게 하나님의 은혜를 베푸시며, 믿음으로 반응하는 자들을 기뻐 받아주시는 분이십니다.\n\n묵상 질문\n1. 백부장처럼 "말씀만 하소서"라고 고백할 수 있는 믿음이 내게 있나요?\n2. 예수님께서 먼저 다가오셔서 위로하신 경험이 있다면 나누어 보세요.\n3. 용서받은 감격이 내 삶에서 어떤 모습으로 나타나고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-03', E'예수의 치유와 가르침 (누가복음 8장)', E'누가복음 8장', E'누가복음 8장은 하나님 나라의 씨앗이 어떻게 자라나는지를 보여주는 귀중한 그림입니다. 예수님께서 각 성과 마을을 다니시며 하나님 나라를 선포하실 때, 그 곁에는 열두 제자뿐 아니라 고침받은 여인들도 함께했습니다. 막달라 마리아, 요안나, 수산나 - 이들은 모두 예수님께 치유받은 후 자신의 소유로 예수님 일행을 섬기는 사람들이었습니다.\n\n씨 뿌리는 자의 비유는 하나님 나라 복음이 사람들에게 어떻게 받아들여지는지를 보여줍니다. 같은 씨앗이라도 떨어진 땅에 따라 결과가 달라집니다. 길가, 바위, 가시떨기, 그리고 좋은 땅. 예수님은 이 비유를 통해 말씀을 듣는 것만으로는 충분하지 않으며, "착하고 좋은 마음으로 말씀을 듣고 지키어 인내로 결실하는"(눅 8:15) 삶이 필요함을 가르치십니다.\n\n등불의 비유가 이어집니다. 숨겨진 것은 드러나고, 감추어진 것은 알려지게 됩니다. 하나님 나라의 진리는 등경 위의 등불처럼 모든 사람에게 빛을 비추도록 되어 있습니다. 그리고 예수님은 혈연을 넘어서는 새로운 가족 개념을 제시하십니다. 하나님의 말씀을 듣고 행하는 사람이 바로 예수님의 참된 가족입니다.\n\n8장 후반부는 예수님의 권능을 생생하게 보여줍니다. 광풍을 잠잠케 하시고, 군대 귀신을 쫓아내시며, 열두 해 혈루증 여인을 고치시고, 죽은 야이로의 딸을 살리십니다. 이 네 가지 이적은 자연, 영적 세계, 질병, 그리고 죽음까지도 다스리시는 예수님의 완전한 권세를 드러냅니다.\n\n특히 주목할 점은 예수님께서 각 상황에서 보이신 반응입니다. 제자들의 약한 믿음 앞에서는 "너희 믿음이 어디 있느냐" 물으시고, 귀신에서 해방된 사람에게는 "집으로 돌아가 하나님이 네게 어떻게 큰 일을 행하셨는지를 말하라" 명하시며, 혈루증 여인에게는 "네 믿음이 너를 구원하였다" 선포하십니다. 예수님은 각 사람의 필요와 상황에 맞는 말씀과 치유를 주시는 분이십니다.', E'오늘의 핵심\n예수님은 하나님 나라의 씨앗을 뿌리시며, 자연과 영적 세계, 질병과 죽음까지 다스리는 완전한 권세로 각 사람의 필요에 응답하시는 구원자이십니다.\n\n묵상 질문\n1. 내 마음은 하나님의 말씀을 받는 어떤 밭인가요? 좋은 땅이 되려면 무엇이 필요할까요?\n2. 예수님께서 폭풍을 잔잔케 하신 것처럼, 내 삶의 어떤 폭풍 앞에서 주님의 도우심이 필요한가요?\n3. 하나님께서 내게 행하신 큰 일을 누구에게 전해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-04', E'한 영혼 사랑에 대한 예수의 가르침 (누가복음 1장)', E'누가복음 1장', E'누가복음은 의사였던 누가가 데오빌로에게 예수 그리스도에 관한 모든 일을 "차례대로" 기록한 복음서입니다. 누가는 철저한 조사와 목격자들의 증언을 바탕으로 구원의 역사가 어떻게 시작되었는지를 보여줍니다. \n\n침묵의 400년을 깨뜨리는 놀라운 소식이 성전에서 시작됩니다. 제사장 사가랴가 성소에서 분향하던 중 천사 가브리엘을 만나게 되는데, 천사는 그의 아내 엘리사벳이 아들을 낳을 것이며 그 이름을 요한이라 하라고 전합니다. 사가랴와 엘리사벳은 "하나님 앞에 의인"으로 살았으나 나이가 많도록 자녀가 없었습니다. 그런 그들에게 주어진 약속의 아들은 "주 앞에 큰 자가 되며" 엘리야의 심령과 능력으로 백성을 하나님께로 돌아오게 할 것이라는 사명을 받습니다.\n\n여섯 달 후, 같은 천사 가브리엘이 갈릴리 나사렛의 한 처녀 마리아를 찾아갑니다. "은혜를 받은 자여 평안할지어다"라는 인사와 함께 더욱 놀라운 소식을 전합니다. 성령으로 잉태하여 하나님의 아들을 낳으리라는 것입니다. 처녀가 아이를 낳는다는 불가능한 일 앞에서 마리아는 "주의 여종이오니 말씀대로 내게 이루어지이다"라고 순종의 고백을 합니다.\n\n마리아가 엘리사벳을 찾아갔을 때, 엘리사벳의 태중의 아이가 기쁨으로 뛰놀고 엘리사벳은 성령충만하여 마리아를 축복합니다. 이에 마리아는 하나님을 찬양하는 노래를 부르는데, 이는 비천한 자를 높이시고 교만한 자를 낮추시는 하나님의 구원 역사를 선포하는 것이었습니다. 요한이 태어났을 때 벙어리가 되었던 사가랴의 입이 열리며, 그는 성령충만하여 메시아의 오심과 구원의 새벽을 예언합니다.\n\n하나님께서는 불가능을 가능케 하시는 분이십니다. 늙어서 아이를 가질 수 없던 엘리사벳에게, 처녀인 마리아에게 각각 특별한 아들을 주십니다. 한 아이는 메시아의 길을 예비할 선구자로, 다른 아이는 온 인류를 구원할 메시아로 오십니다. 이 모든 일은 아브라함에게 약속하신 것을 신실하게 이루시는 하나님의 은혜였습니다.', E'오늘의 핵심\n400년의 침묵을 깨고 하나님께서는 구원의 역사를 시작하시는데, 불가능한 상황 속에서도 믿음으로 순종하는 사람들을 통해 그 약속을 이루어가십니다.\n\n묵상 질문\n1. 오랜 기다림 끝에 응답받은 사가랴와 엘리사벳의 이야기가 나에게 주는 위로는 무엇인가요?\n2. "주의 여종이오니 말씀대로 내게 이루어지이다"라는 마리아의 고백을 나도 할 수 있을까요?\n3. 하나님의 약속을 믿고 기다리며 순종해야 할 나의 영역은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-05', E'한 영혼 사랑에 대한 예수의 가르침 (누가복음 2장)', E'누가복음 2장', E'로마 황제 아구스도의 인구조사 명령은 온 제국을 움직이게 했고, 요셉과 마리아도 베들레헴으로 향해야 했습니다. 인간의 정치적 결정처럼 보이는 이 사건이 실은 미가 선지자가 예언한 메시아 탄생 장소에 대한 하나님의 섭리였음을 누가는 보여줍니다. 여관에 방이 없어 구유에 뉘인 아기의 모습은 이 세상에 오신 구주의 겸손과 낮아지심을 상징적으로 드러냅니다.\n\n천사들의 찬양이 울려 퍼진 그 밤, 가장 먼저 복음을 들은 이들은 들판의 목자들이었습니다. 당시 사회에서 천대받던 이들에게 "온 백성에게 미칠 큰 기쁨의 좋은 소식"(눅 2:10)이 전해진 것입니다. 목자들은 천사의 말을 듣고 즉시 베들레헴으로 달려가 아기를 경배했으며, 본 것을 사람들에게 전하는 최초의 복음 전도자가 되었습니다. 마리아는 이 모든 일을 마음에 새기며 묵상했습니다.\n\n정결예식을 위해 성전을 찾은 마리아와 요셉은 놀라운 만남을 경험합니다. 성령의 감동으로 성전에 온 시므온은 아기 예수를 안고 "만민의 구원"이자 "이방을 비추는 빛"이라 선포합니다. 팔십사 세의 여선지자 안나도 하나님께 감사하며 예루살렘의 구속을 기다리는 모든 이에게 이 아기에 대해 증거했습니다. 이들은 오랜 기다림 끝에 메시아를 알아본 믿음의 사람들이었습니다.\n\n열두 살 된 예수님은 유월절 성전에서 율법 선생들과 토론하시며 놀라운 지혜를 보이셨습니다. 부모가 애타게 찾자 "내가 내 아버지 집에 있어야 될 줄을 알지 못하셨나이까"라고 답하신 예수님의 말씀은 그분의 신적 정체성을 암시합니다. 그럼에도 예수님은 나사렛으로 돌아가 부모에게 순종하며 성장하셨습니다. 하나님의 아들이 인간의 성장 과정을 온전히 경험하시며 우리와 같은 인간이 되신 성육신의 신비가 여기에 담겨 있습니다.', E'오늘의 핵심\n하나님의 아들 예수님은 가장 낮고 천한 모습으로 이 땅에 오셔서 목자들과 같은 소외된 이들에게 먼저 복음을 전하셨으며, 참 하나님이시면서도 참 인간으로서 성장의 과정을 거치셨습니다.\n\n묵상 질문\n1. 구유에 누이신 아기 예수의 모습이 오늘 나에게 전하는 메시지는 무엇일까요?\n2. 시므온과 안나처럼 오랜 기다림 끝에 주님을 만나는 기쁨을 경험해 보셨나요?\n3. 예수님이 부모에게 순종하며 자라가신 모습을 통해 내 삶의 순종은 어떠해야 할지 생각해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-07', E'한 영혼 사랑에 대한 예수의 가르침 (누가복음 3장)', E'누가복음 3장', E'로마의 디베료 황제가 통치한 지 15년, 본디오 빌라도가 유대 총독으로 다스리던 시대에 하나님의 말씀이 광야에서 세례 요한에게 임했습니다. 누가는 당시의 정치적 상황을 구체적으로 기록하면서, 세계사의 한복판에서 하나님의 구원 역사가 시작되고 있음을 보여줍니다. 요한은 이사야 선지자의 예언대로 "광야에서 외치는 자의 소리"가 되어 주의 길을 예비하는 사명을 감당합니다.\n\n세례 요한의 메시지는 단순하면서도 강력했습니다. 그는 회개의 세례를 전파하면서, 아브라함의 자손이라는 혈통적 자부심이 아니라 회개에 합당한 열매를 맺는 삶을 요구했습니다. 세례 받으러 나아온 무리들에게 요한이 제시한 회개의 열매는 매우 구체적이었습니다. 옷 두 벌 있는 자는 없는 자와 나누고, 세리는 정한 세금 외에는 거두지 말고, 군인은 강탈하거나 거짓 고발하지 말라는 것이었습니다. 이는 각자의 삶의 자리에서 정의롭고 자비로운 삶을 살아내는 것이 진정한 회개의 증거임을 가르쳐줍니다.\n\n요한은 자신보다 능력이 많으신 분이 오실 것을 분명히 증언했습니다. 물로 베푸는 자신의 세례와는 달리, 그분은 성령과 불로 세례를 베푸실 것이며, 알곡과 쭉정이를 가르는 심판의 권세를 가지신 분이라고 선포했습니다. 그리고 마침내 예수님께서 요단강에서 세례를 받으실 때, 하늘이 열리고 성령이 비둘기 같은 형체로 임하시며 "너는 내 사랑하는 아들이라"는 하늘 아버지의 음성이 들려왔습니다. 이 장면은 삼위일체 하나님의 계시가 공개적으로 나타난 놀라운 순간이었습니다.\n\n누가는 예수님의 족보를 아담까지, 그리고 하나님까지 거슬러 올라가며 기록합니다. 이는 예수님이 단지 유대인의 메시아일 뿐 아니라 온 인류의 구원자이심을 보여주는 것입니다. 하나님의 아들이신 예수님께서 인류의 역사 속으로 들어오셔서 모든 사람을 위한 구원의 길을 여신 것입니다.', E'오늘의 핵심\n세례 요한은 회개의 열매를 맺는 구체적인 삶의 변화를 요구했고, 예수님의 세례는 하나님의 아들로서의 신분과 온 인류를 위한 구원 사역의 시작을 공개적으로 선포하는 사건이었습니다.\n\n묵상 질문\n1. 세례 요한이 제시한 회개의 열매처럼, 나의 삶의 자리에서 실천해야 할 구체적인 정의와 자비의 행동은 무엇일까요?\n2. 예수님께서 세례 받으실 때 들려온 "너는 내 사랑하는 아들"이라는 음성이 나에게도 들려온다면, 나의 삶은 어떻게 달라질까요?\n3. 누가가 예수님의 족보를 아담과 하나님까지 거슬러 올라간 것처럼, 나는 모든 사람을 하나님의 형상으로 보고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-08', E'한 영혼 사랑에 대한 예수의 가르침 (누가복음 4장)', E'누가복음 4장', E'광야에서 사십 일 동안 금식하신 예수님께 마귀가 다가와 세 가지 시험을 제시합니다. 돌로 떡을 만들라는 육신의 필요에 대한 유혹, 천하만국의 권세와 영광을 주겠다는 세상적 야망에 대한 유혹, 성전 꼭대기에서 뛰어내리라는 하나님을 시험하라는 유혹이었습니다. 예수님께서는 이 모든 시험을 하나님의 말씀으로 물리치셨습니다. "사람이 떡으로만 살 것이 아니라", "주 너의 하나님께 경배하고 다만 그를 섬기라", "주 너의 하나님을 시험하지 말라"는 말씀으로 마귀의 교묘한 유혹을 단호하게 거절하신 것입니다.\n\n성령의 능력으로 갈릴리에 돌아오신 예수님께서는 고향 나사렛의 회당에서 이사야서의 말씀을 읽으셨습니다. "주의 성령이 내게 임하셨으니 이는 가난한 자에게 복음을 전하게 하시려고 내게 기름을 부으시고"(눅 4:18)라는 구절을 통해 예수님께서는 자신이 바로 그 예언의 성취임을 선포하셨습니다. 그러나 고향 사람들은 목수의 아들로만 알았던 예수님의 선포를 받아들이지 못했고, 오히려 분노하여 예수님을 동네 밖으로 쫓아내었습니다.\n\n가버나움으로 가신 예수님의 가르침에는 권위가 있었습니다. 더러운 귀신 들린 사람을 고치시고, 시몬의 장모의 열병을 낫게 하시며, 해 질 무렵에 몰려온 온갖 병자들을 일일이 고쳐주셨습니다. 귀신들조차 예수님을 "하나님의 아들"이라 알아보았지만, 예수님께서는 때가 이르지 않았기에 그들이 말하는 것을 허락하지 않으셨습니다. 날이 밝자 한적한 곳으로 가신 예수님께서는 자신을 붙잡으려는 무리들에게 다른 동네에서도 하나님 나라의 복음을 전해야 한다고 말씀하시며, 이것이 바로 자신이 보내심을 받은 사명임을 분명히 하셨습니다.', E'오늘의 핵심\n예수님께서는 광야의 시험을 말씀으로 이기시고, 성령의 능력으로 가난한 자들에게 복음을 전하며 병든 자들을 고치시는 메시아의 사역을 시작하셨습니다.\n\n묵상 질문\n1. 내 삶에서 마주하는 유혹들을 하나님의 말씀으로 이겨낼 준비가 되어 있나요?\n2. 예수님처럼 소외된 이웃에게 복음을 전하고 섬기는 일에 헌신하고 있나요?\n3. 하나님께서 나에게 주신 사명을 분명히 알고 그 길을 가고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-09', E'한 영혼 사랑에 대한 예수의 가르침 (누가복음 5장)', E'누가복음 5장', E'게네사렛 호숫가에서 밤새 허탕만 친 어부들에게 예수님께서 찾아오셨습니다. 베드로의 빈 배에 오르신 예수님은 깊은 곳으로 나가 그물을 던지라고 말씀하십니다. 전문 어부의 경험과 상식을 뛰어넘는 이 요구에 베드로는 "말씀에 의지하여" 순종합니다. 그 결과는 놀라웠습니다. 두 배가 가라앉을 정도로 많은 고기가 잡혔고, 베드로는 예수님 앞에 엎드려 자신이 죄인임을 고백합니다. 갈릴리 호수의 기적은 단순한 풍어의 사건이 아니라, 인간의 한계를 넘어서는 하나님의 능력과 은혜를 보여주는 표징이었습니다.\n\n예수님의 사역은 종교 지도자들의 틀을 깨뜨리는 것이었습니다. 온몸에 나병이 든 사람을 손으로 만지시고, 중풍병자의 죄를 사하신다고 선언하시며, 세리 레위를 제자로 부르십니다. 바리새인들은 예수님께서 세리와 죄인들과 함께 식사하시는 것을 비난했지만, 예수님은 "건강한 자에게는 의사가 쓸 데 없고 병든 자에게라야 쓸 데 있나니"라고 응답하십니다. 이는 예수님께서 이 땅에 오신 목적이 의인이 아닌 죄인을 부르시기 위함임을 분명히 보여줍니다.\n\n새 포도주는 새 부대에 담아야 한다는 비유를 통해, 예수님은 복음이 기존의 종교적 틀과 형식을 넘어서는 새로운 생명의 메시지임을 가르치십니다. 율법의 형식에 갇혀 있던 종교 지도자들과 달리, 예수님은 상한 심령을 치유하시고 소외된 자들을 품으시는 사랑의 복음을 선포하셨습니다. 그분의 권능 앞에서 죄는 사함받고, 질병은 치유되며, 절망은 소망으로 변화됩니다.', E'오늘의 핵심\n예수님은 인간의 경험과 한계를 뛰어넘는 하나님의 권능으로 죄인을 부르시고 새 생명을 주시는 구원자이십니다.\n\n묵상 질문\n1. 베드로처럼 "말씀에 의지하여" 순종해야 할 일이 내 삶에 있나요?\n2. 예수님께서 세리와 죄인들과 함께하신 것처럼, 내가 품어야 할 소외된 이웃은 누구인가요?\n3. 낡은 가죽부대 같은 내 고정관념이 복음의 새로운 역사를 막고 있지는 않나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-10', E'한 영혼 사랑에 대한 예수의 가르침 (누가복음 6장)', E'누가복음 6장', E'안식일 논쟁을 통해 예수님은 율법의 참된 정신이 무엇인지를 분명히 보여주십니다. 바리새인들이 제자들의 행동을 문제 삼았을 때, 예수님은 다윗의 예를 들어 응답하십니다. 생명을 살리는 일이 율법의 형식보다 우선한다는 진리를 가르쳐 주신 것입니다. 이어지는 회당에서의 치유 사건도 마찬가지입니다. 손 마른 사람을 고치시면서 "안식일에 선을 행하는 것과 악을 행하는 것, 생명을 구하는 것과 죽이는 것, 어느 것이 옳으냐"(눅 6:9)고 물으십니다. 안식일의 주인이신 예수님은 그날이 생명을 회복하는 날임을 선포하셨습니다.\n\n밤새도록 기도하신 후 열두 제자를 택하신 일은 새로운 이스라엘, 곧 하나님 나라 공동체의 시작을 알리는 중요한 순간이었습니다. 평지 설교에서 선포하신 팔복과 화는 세상의 가치관을 완전히 뒤집어 놓습니다. 가난한 자, 주린 자, 우는 자가 복이 있다는 말씀은 하나님 나라가 세상과는 전혀 다른 질서로 움직임을 보여줍니다. \n\n특별히 원수 사랑의 명령은 하나님 나라 백성의 정체성을 극명하게 드러냅니다. 사랑하는 자만 사랑하는 것은 죄인들도 하는 일입니다. 그러나 예수님을 따르는 제자들은 원수를 사랑하고, 미워하는 자를 선대하며, 저주하는 자를 축복해야 합니다. 이것이 "지극히 높으신 이의 아들"이 되는 길입니다. 하나님께서 은혜를 모르는 자와 악한 자에게도 인자하신 것처럼, 우리도 그런 자비를 실천해야 합니다.\n\n말씀의 마지막 부분은 듣는 것과 행하는 것의 차이를 반석 위의 집과 모래 위의 집으로 비유하십니다. 예수님의 말씀을 듣기만 하고 행하지 않는 것은 주추 없이 집을 짓는 것과 같습니다. 진정한 제자도는 듣는 것에서 그치지 않고 삶으로 실천할 때 완성됩니다.', E'오늘의 핵심\n예수님은 안식일의 참된 의미를 회복하시고, 세상과는 전혀 다른 하나님 나라의 가치관을 제시하시며, 원수까지도 사랑하는 급진적인 사랑을 명령하십니다.\n\n묵상 질문\n1. 내가 지키고 있는 종교적 형식이 오히려 생명을 살리는 일을 방해하고 있지는 않나요?\n2. 하나님의 자비하심을 닮아 원수를 사랑하기 어려운 이유는 무엇일까요?\n3. 예수님의 말씀을 듣고도 실천하지 못하는 영역이 있다면 어떤 부분인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-11', E'약자를 위한 배려 (누가복음 10장)', E'누가복음 10장', E'예수님께서 칠십 명의 제자들을 각 동네로 파송하시며 하나님 나라의 복음을 전하게 하십니다. 이들에게 주신 권능은 놀라운 것이었습니다. 귀신들까지도 예수님의 이름 앞에 굴복했기 때문입니다. 그러나 예수님은 제자들에게 더 중요한 진리를 가르쳐 주십니다. "귀신들이 너희에게 항복하는 것으로 기뻐하지 말고 너희 이름이 하늘에 기록된 것으로 기뻐하라"(눅 10:20)는 말씀을 통해, 하나님의 자녀 됨이 어떤 능력보다 소중함을 일깨워 주신 것입니다.\n\n율법교사가 영생의 길을 묻자, 예수님은 사랑의 계명으로 답하십니다. 하나님 사랑과 이웃 사랑이 영생으로 가는 길임을 확인시켜 주신 것입니다. 그런데 율법교사는 자기를 정당화하려는 마음으로 "내 이웃이 누구입니까?"라고 되묻습니다. 예수님은 선한 사마리아인의 비유를 통해 참된 이웃 사랑의 본질을 보여주십니다. 유대인들이 멸시하던 사마리아인이 오히려 강도 만난 자에게 자비를 베푸는 참된 이웃이 되었다는 이 비유는, 사랑에는 경계가 없음을 가르쳐 줍니다. 종교적 신분이나 민족적 편견을 넘어서는 것이 진정한 사랑입니다.\n\n마르다와 마리아의 집에서 보여주신 예수님의 가르침 또한 우리에게 중요한 통찰을 제공합니다. 분주하게 섬기는 마르다와 달리 마리아는 예수님의 발치에 앉아 말씀을 듣고 있었습니다. 예수님은 마리아가 "좋은 편을 택하였다"고 말씀하시며, 하나님의 말씀을 듣는 것이 모든 활동보다 우선되어야 함을 가르치십니다. 섬김도 중요하지만, 먼저 주님과의 친밀한 교제 가운데서 그분의 음성을 듣는 것이 제자의 삶에서 가장 본질적인 일임을 보여주신 것입니다.', E'오늘의 핵심\n예수님은 제자들에게 능력보다 하늘 시민권의 소중함을, 율법의 행위보다 경계 없는 사랑의 실천을, 분주한 섬김보다 말씀 듣는 것의 우선순위를 가르치십니다.\n\n묵상 질문\n1. 나는 하나님께서 주신 은사와 능력보다 구원받은 자녀 됨을 더 기뻐하고 있나요?\n2. 내가 선을 긋고 사랑하기를 주저하는 ''사마리아인''은 누구인가요?\n3. 오늘 하루 분주한 일상 속에서도 주님의 발치에 앉을 시간을 구별할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-12', E'약자를 위한 배려 (누가복음 11장)', E'누가복음 11장', E'예수님께서 기도하시는 모습을 본 제자들이 기도를 가르쳐 달라고 요청합니다. 예수님은 하나님을 "아버지"로 부르며 시작하는 기도를 가르치시는데, 이는 당시 유대인들에게는 혁명적인 가르침이었습니다. 하나님의 이름이 거룩히 여김을 받고 그의 나라가 임하기를 구하는 것으로 시작하여, 일용할 양식과 죄 사함, 그리고 시험으로부터의 보호를 구하는 내용으로 이어집니다. \n\n이어서 예수님은 밤중에 찾아온 친구에게 떡을 꾸어달라는 비유를 통해 끈질긴 기도의 중요성을 가르치십니다. 하나님은 좋은 것을 구하는 자녀들에게 성령을 주시는 좋으신 아버지임을 강조하시며, "구하라 그러면 너희에게 주실 것이요"라는 약속의 말씀을 주십니다.\n\n예수님께서 귀신을 쫓아내시자 일부 사람들은 바알세불을 힘입어 한다고 비난합니다. 그러나 예수님은 사탄이 스스로 분쟁하면 그 나라가 설 수 없다는 논리로 반박하시고, 오히려 하나님의 나라가 이미 임했음을 선포하십니다. 더러운 귀신이 나갔다가 더 악한 귀신 일곱을 데리고 돌아오는 비유를 통해, 단순히 악을 제거하는 것이 아니라 하나님의 말씀으로 채워야 함을 가르치십니다.\n\n바리새인의 초청을 받아 식사하시던 중, 예수님은 그들의 외식을 날카롭게 지적하십니다. 잔과 대접의 겉은 깨끗이 하면서 속에는 탐욕과 악독이 가득한 그들의 위선을 폭로하시고, 십일조는 철저히 지키면서 정작 중요한 공의와 하나님 사랑은 버린다고 책망하십니다. 율법교사들에게도 지기 어려운 짐을 사람들에게 지우면서 자신들은 손가락 하나 대지 않는다고 질책하십니다. 예수님의 이러한 가르침은 겉치레가 아닌 진정한 마음의 변화를 요구하시는 하나님의 뜻을 분명히 보여줍니다.', E'오늘의 핵심\n예수님은 하나님을 아버지로 부르며 간구하는 친밀한 기도와 함께, 겉모습이 아닌 내면의 진실함을 요구하시며 형식적 신앙의 위선을 철저히 드러내십니다.\n\n묵상 질문\n1. 내 기도가 진정으로 하나님의 나라와 뜻을 구하고 있나요, 아니면 내 필요만을 채우려 하고 있나요?\n2. 신앙생활에서 남에게 보이는 모습과 하나님 앞에서의 진짜 모습 사이에 괴리는 없나요?\n3. 하나님의 말씀을 듣고 지키는 삶을 위해 오늘 내가 버려야 할 외식적 습관은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-14', E'약자를 위한 배려 (누가복음 12장)', E'누가복음 12장', E'바리새인들의 외식을 경계하라고 가르치신 예수님께서는 제자들에게 참된 신앙의 모습이 무엇인지 보여주십니다. 수만 명의 무리가 모여들 정도로 예수님의 명성이 높아졌지만, 주님은 오히려 제자들에게 겸손과 진실함을 먼저 가르치십니다. 감추어진 것이 드러나지 않을 것이 없다는 말씀은 하나님 앞에서 우리의 모든 것이 투명하게 보인다는 진리를 일깨워줍니다.\n\n예수님은 제자들에게 진정으로 두려워해야 할 분이 누구인지 분명히 가르치십니다. 몸은 죽여도 그 이상 아무것도 할 수 없는 사람을 두려워하지 말고, 영혼까지 심판하실 수 있는 하나님을 경외하라는 말씀입니다. 그런데 이 두려우신 하나님이 동시에 우리의 머리털까지 세시는 세심한 사랑의 하나님이시라는 역설적 진리가 우리를 놀라게 합니다. 참새 다섯 마리가 두 앗사리온에 팔리는 하찮은 존재이지만, 하나님은 그 하나도 잊지 않으신다는 말씀은 우리를 향한 하나님의 깊은 관심과 돌보심을 보여줍니다.\n\n한 부자의 비유는 물질에 대한 우리의 관점을 근본적으로 바꾸어 놓습니다. 풍성한 소출로 곳간을 더 크게 지으려던 부자의 계획은 어리석음의 극치였습니다. "오늘 밤에 네 영혼을 도로 찾으리니"(눅 12:20)라는 하나님의 선언은 생명의 주권이 오직 하나님께 있음을 분명히 보여줍니다. 예수님은 이 비유를 통해 자기를 위해 재물을 쌓되 하나님께 대하여는 부요하지 못한 자의 비참한 결말을 경고하십니다.\n\n이어지는 말씀에서 예수님은 제자들에게 일용할 양식과 의복을 위해 염려하지 말라고 가르치십니다. 까마귀도 먹이시고 백합화도 입히시는 하나님께서 그분의 자녀들을 돌보지 않으실 리 없다는 확신을 주십니다. 예수님은 세상 백성들이 구하는 것과는 다른 가치, 곧 하나님의 나라를 먼저 구하라고 명하십니다. 이는 단순히 물질을 포기하라는 가르침이 아니라, 우선순위를 바르게 정하라는 지혜의 말씀입니다. 허리에 띠를 띠고 등불을 켜고 깨어 있으라는 종말론적 권면은 우리가 늘 영적으로 각성된 상태로 살아가야 함을 일깨워줍니다.', E'오늘의 핵심\n예수님은 외식적 신앙을 버리고 하나님을 경외하며, 물질이 아닌 하나님 나라를 먼저 구하는 참된 제자의 삶을 가르치십니다.\n\n묵상 질문\n1. 내 신앙생활에서 남의 눈을 의식하여 꾸며낸 모습은 무엇일까요?\n2. 하나님보다 물질적 안정을 더 의지하고 있는 영역이 있다면 어디일까요?\n3. 주님이 오늘 오신다면 나는 신실한 종으로 발견될 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-15', E'약자를 위한 배려 (누가복음 13장)', E'누가복음 13장', E'당시 유대인들 사이에서는 고난을 죄의 결과로 여기는 인과응보 사상이 깊이 자리잡고 있었습니다. 빌라도가 갈릴리 사람들을 학살한 사건과 실로암 망대가 무너져 열여덟 명이 죽은 참사를 두고도 사람들은 그들의 죄 때문이라고 생각했습니다. 그러나 예수님께서는 이러한 통념을 정면으로 반박하시며 "너희도 만일 회개하지 아니하면 다 이와 같이 망하리라"(눅 13:3)고 경고하십니다. 재난과 고통의 문제를 남의 죄로 돌리는 대신, 자신의 회개가 시급함을 깨닫게 하신 것입니다.\n\n이어지는 무화과나무 비유는 하나님의 인내하시는 사랑을 보여줍니다. 삼 년 동안 열매를 맺지 못한 나무를 당장 찍어버리지 않고 한 해를 더 기다리시는 주인의 모습은, 회개의 기회를 주시는 하나님의 은혜를 나타냅니다. 포도원지기가 나무 주위를 파고 거름을 주겠다는 간청은 우리를 위한 예수님의 중보 사역을 연상시킵니다.\n\n안식일에 십팔 년 동안 귀신 들려 꼬부라진 여인을 고치신 일화는 율법의 참된 정신이 무엇인지 보여줍니다. 회당장은 안식일 규정에만 매여 있었지만, 예수님께서는 사탄에게 매인 아브라함의 딸을 푸는 것이야말로 안식일에 합당한 일임을 선포하십니다. 겨자씨와 누룩의 비유를 통해 하나님 나라가 작게 시작되지만 놀랍게 성장할 것을 가르치신 후, 예수님께서는 좁은 문으로 들어가기를 힘쓰라고 권면하십니다.\n\n예루살렘을 향한 예수님의 애끓는 탄식은 하나님의 마음을 그대로 드러냅니다. 선지자들을 죽이고 하나님의 사자들을 배척한 도성을 향해, 암탉이 새끼를 품듯 보호하고 싶으셨으나 그들이 원하지 않았다고 한탄하십니다. 이는 구원을 거부하는 인간의 완고함과 그럼에도 불구하고 포기하지 않으시는 하나님의 사랑을 동시에 보여주는 장면입니다.', E'오늘의 핵심\n예수님께서는 인과응보의 틀에 갇힌 종교적 사고를 깨뜨리시고, 회개와 은혜의 긴급성을 가르치시며, 좁은 문으로 들어가는 참된 구원의 길을 제시하십니다.\n\n묵상 질문\n1. 남의 고난을 보며 정죄하기보다 나 자신의 회개가 필요함을 깨닫고 있나요?\n2. 열매 맺지 못하는 내 삶의 영역에서 하나님의 인내하심을 경험한 적이 있나요?\n3. 종교적 규칙에 매여 정작 사랑의 실천을 놓치고 있는 부분은 없을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-16', E'약자를 위한 배려 (누가복음 14장)', E'누가복음 14장', E'안식일에 바리새인 지도자의 집에서 벌어진 일은 예수님의 하나님 나라 가치관을 선명하게 보여줍니다. 수종병 든 사람을 고치시는 것으로 시작된 이 날의 가르침은, 당시 종교 지도자들이 붙잡혀 있던 형식주의와 위선을 드러내고 있습니다. 예수님께서는 "너희 중에 누가 그 아들이나 소가 우물에 빠졌으면 안식일에라도 곧 끌어내지 않겠느냐"(눅 14:5)고 물으시며, 생명을 살리는 일이 종교적 규정보다 우선됨을 가르쳐 주십니다.\n\n이어지는 잔치의 비유들은 하나님 나라의 역설적 질서를 보여줍니다. 높은 자리를 탐하는 이들에게 예수님께서는 스스로 낮은 자리를 택하라고 가르치십니다. 더 나아가 잔치를 베풀 때는 갚을 능력이 없는 가난한 자들과 몸 불편한 자들을 청하라고 말씀하십니다. 이는 단순한 예의범절을 넘어서는 하나님 나라의 근본 원리를 담고 있습니다. 하나님의 은혜는 대가를 바라지 않는 무조건적 사랑에서 흘러나오기 때문입니다.\n\n큰 잔치 비유는 하나님의 구원 초청에 대한 인간의 반응을 날카롭게 묘사합니다. 초청받은 이들은 밭, 소, 결혼 등 세상일을 핑계로 잔치 참여를 거부합니다. 그러자 주인은 거리의 가난한 자들과 장애인들을 데려오라고 명령합니다. 이는 유대인들이 거부한 복음이 이방인과 소외된 이들에게로 향하게 될 것을 암시합니다. \n\n마지막으로 예수님께서는 제자도의 값비싼 대가를 분명히 하십니다. 가족보다 예수님을 더 사랑하고, 자기 십자가를 지며, 모든 소유를 버릴 각오가 되어 있어야 한다고 말씀하십니다. 이는 무모한 열정이 아니라 신중한 헌신을 요구하는 것입니다. 망대를 세우거나 전쟁을 치르기 전에 계산하듯, 제자가 되기로 결심하기 전에 그 대가를 깊이 생각해야 합니다. 맛을 잃은 소금이 버려지듯, 중도에 포기하는 것보다는 처음부터 신중하게 결단하는 것이 중요함을 가르쳐 주십니다.', E'오늘의 핵심\n예수님께서는 안식일 논쟁과 잔치 비유를 통해 하나님 나라의 역설적 질서를 보여주시며, 참된 제자도는 모든 것을 버릴 각오와 함께하는 신중한 헌신임을 가르치십니다.\n\n묵상 질문\n1. 종교적 형식보다 생명과 사랑을 우선시하는 예수님의 가르침을 내 삶에서 어떻게 실천할 수 있을까요?\n2. 대가를 바라지 않고 베푸는 사랑을 실천하기 어려운 이유는 무엇일까요?\n3. 예수님의 제자가 되기 위해 내가 버려야 할 것과 감당해야 할 십자가는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-17', E'약자를 위한 배려 (누가복음 15장)', E'누가복음 15장', E'세리와 죄인들이 예수님의 말씀을 듣기 위해 가까이 나아오자, 바리새인과 서기관들은 예수님이 죄인들과 함께 식사하신다며 수군거렸습니다. 당시 유대 사회에서 세리와 죄인들은 하나님의 백성 공동체에서 배제된 사람들이었기에, 종교 지도자들은 예수님의 행동을 이해할 수 없었습니다. 이에 예수님께서는 세 가지 비유를 통해 잃어버린 자를 향한 하나님의 마음을 보여주십니다.\n\n잃은 양의 비유에서 목자는 아흔아홉 마리를 들에 두고 한 마리를 찾아 나섭니다. 잃은 드라크마의 비유에서 여인은 등불을 켜고 집을 쓸며 부지런히 동전 하나를 찾습니다. 이 두 비유는 하나님께서 잃어버린 한 영혼을 얼마나 소중히 여기시는지를 보여줍니다. 특히 찾은 후의 기쁨을 이웃과 함께 나누는 모습은 "죄인 한 사람이 회개하면 하늘에서는 회개할 것 없는 의인 아흔아홉으로 말미암아 기뻐하는 것보다 더하리라"(눅 15:7)는 말씀으로 이어집니다.\n\n탕자의 비유는 더욱 깊은 차원의 하나님 사랑을 보여줍니다. 아버지의 재산을 탕진하고 돼지치기로 전락한 둘째 아들이 돌아오자, 아버지는 거리가 먼데도 달려가 목을 안고 입을 맞춥니다. 가장 좋은 옷과 가락지, 신발을 주고 잔치를 베푸는 아버지의 모습은 회개하는 죄인을 향한 하나님의 무조건적인 사랑을 보여줍니다. 맏아들의 불평에도 아버지는 "네 동생은 죽었다가 살아났으며 내가 잃었다가 얻었기로 우리가 즐거워하고 기뻐하는 것이 마땅하다"고 말씀합니다. 이는 바리새인들처럼 자신의 의로움에 갇혀 하나님의 은혜를 이해하지 못하는 이들을 향한 초청이기도 합니다.', E'오늘의 핵심\n예수님께서는 세 가지 비유를 통해 잃어버린 한 영혼을 찾아 구원하시는 하나님의 열정적인 사랑과 회개하는 죄인을 맞이하시는 하나님의 무조건적인 은혜를 보여주십니다.\n\n묵상 질문\n1. 나는 혹시 맏아들처럼 하나님의 은혜보다 내 의로움에 갇혀 있지는 않나요?\n2. 하나님께서 나를 찾아 구원하신 그 사랑을 깊이 묵상해 보셨나요?\n3. 내 주변의 잃어버린 영혼들을 향한 하나님의 마음을 품고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-18', E'약자를 위한 배려 (누가복음 16장)', E'누가복음 16장', E'누가복음 16장은 물질을 대하는 제자의 자세와 영원한 생명의 문제를 깊이 있게 다루고 있습니다. 예수님께서는 먼저 불의한 청지기의 비유를 통해 우리에게 지혜로운 청지기직에 대해 가르치십니다. 이 청지기는 해고 통보를 받자 미래를 대비해 주인에게 빚진 자들의 빚을 탕감해 주는 기지를 발휘합니다. 주인은 오히려 그의 지혜로운 처신을 칭찬했는데, 이는 그가 위기 상황에서 미래를 준비하는 통찰력을 보였기 때문입니다. 예수님은 이를 통해 "불의의 재물로 친구를 사귀라"(눅 16:9)고 가르치시는데, 이는 우리가 가진 물질을 영원한 관점에서 사용하라는 뜻입니다. \n\n작은 것에 충성된 자가 큰 것에도 충성될 수 있다는 가르침은 일상의 물질 관리가 곧 영적 성숙도와 연결됨을 보여줍니다. 우리는 하나님과 재물을 겸하여 섬길 수 없으며, 둘 중 하나를 선택해야 합니다. 돈을 사랑하던 바리새인들이 이 가르침을 비웃자, 예수님은 사람 앞에서 높임받는 것이 하나님 앞에서는 미움받을 수 있음을 경고하십니다.\n\n이어지는 부자와 나사로의 이야기는 물질주의의 결말을 극명하게 보여줍니다. 호화롭게 살던 부자는 자기 대문 앞의 거지 나사로를 외면했고, 죽음 후에는 그들의 운명이 완전히 뒤바뀝니다. 음부에서 고통받는 부자와 아브라함의 품에서 위로받는 나사로의 모습은 현세의 삶이 영원을 결정함을 보여줍니다. 부자가 뒤늦게 형제들에게라도 경고하고자 했지만, 아브라함은 이미 주어진 말씀에 순종하지 않는 자들은 기적을 보아도 믿지 않을 것임을 일깨워줍니다. 하나님의 나라는 물질의 풍요가 아닌 하나님의 말씀에 대한 순종과 이웃 사랑의 실천으로 이루어집니다.', E'오늘의 핵심\n예수님은 우리가 맡은 물질을 영원한 관점에서 지혜롭게 사용하며, 작은 일에 충성함으로써 하나님 나라의 참된 부요함을 누리도록 가르치십니다.\n\n묵상 질문\n1. 나는 물질을 영원을 위해 사용하고 있나요, 아니면 현재의 안락함만을 위해 사용하고 있나요?\n2. 내 주변의 ''나사로''를 외면하고 있지는 않은지 돌아볼 수 있을까요?\n3. 작은 일상의 충성이 어떻게 영적 성장으로 이어질지 기도해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-19', E'약자를 위한 배려 (누가복음 17장)', E'누가복음 17장', E'예수님께서는 예루살렘으로 향하시는 길에서 제자들에게 공동체의 삶과 하나님 나라의 본질에 관한 중요한 가르침을 주십니다. 먼저 실족하게 하는 일의 심각성을 경고하시면서, 특히 믿음이 연약한 자들을 넘어뜨리는 것이 얼마나 큰 죄인지를 강조하십니다. 동시에 형제가 죄를 지었을 때 경고하되, 회개하면 하루에 일곱 번이라도 용서하라는 놀라운 은혜의 원리를 제시하십니다. \n\n이런 가르침에 부담을 느낀 제자들이 "우리에게 믿음을 더하소서"라고 간구하자, 예수님께서는 겨자씨만한 작은 믿음이라도 있다면 불가능해 보이는 일도 가능하다고 말씀하십니다. 그러나 곧이어 종의 비유를 통해 우리가 하나님 앞에서는 무익한 종에 불과하며, 마땅히 해야 할 일을 했을 뿐임을 깨우쳐 주십니다.\n\n사마리아와 갈릴리 사이를 지나시던 예수님께서 열 명의 나병환자를 만나 고쳐주신 사건은 감사와 믿음의 본질을 보여줍니다. 유대인이 아닌 사마리아 사람만이 돌아와 감사를 표현했다는 사실은, 하나님의 은혜가 민족과 신분의 경계를 넘어선다는 것을 분명히 드러냅니다. "네 믿음이 너를 구원하였느니라"는 예수님의 선언은 단순한 육체의 치유를 넘어 전인적 구원을 의미합니다.\n\n바리새인들이 하나님 나라가 언제 임하는지 묻자, 예수님께서는 하나님의 나라는 눈에 보이는 방식으로 오는 것이 아니라 "너희 안에 있느니라"고 말씀하십니다. 이는 하나님의 나라가 예수님 자신과 함께 이미 그들 가운데 임했음을 의미합니다. 마지막으로 재림의 날에 대해 말씀하시면서, 노아와 롯의 시대처럼 사람들이 일상에 매여 있다가 갑작스럽게 심판을 맞게 될 것을 경고하십니다. 그날에는 세상의 것에 미련을 두지 말고, 자기 목숨을 보전하려는 자는 오히려 잃을 것이라는 역설적 진리를 가르치십니다.', E'오늘의 핵심\n예수님께서는 공동체 안에서의 용서와 섬김, 감사하는 믿음, 그리고 이미 임했으나 아직 완성되지 않은 하나님 나라의 긴장 속에서 깨어 있는 삶을 살라고 가르치십니다.\n\n묵상 질문\n1. 나는 연약한 믿음의 형제자매들을 실족하게 하지는 않았는지, 또한 용서를 아끼고 있지는 않은지 돌아볼 수 있을까요?\n2. 하나님의 은혜를 받고도 감사를 잊고 살아가는 아홉 명의 나병환자처럼 살고 있지는 않나요?\n3. 하나님의 나라가 내 안에 있다는 말씀이 오늘 내 삶에 어떤 의미가 있을까요?');
